INSERT INTO questions (theme, type_media, url_media, question, reponse_A, reponse_B, reponse_C, reponse_D, bonne_reponse, anecdote) VALUES
('Gastronomie', 'image', 'https://upload.wikimedia.org/wikipedia/commons/a/ad/Jielbeaumadier_welsh_2010.jpg', 'Quel ingrédient est indispensable pour gratiner un véritable Welsh ?', 'Le Maroilles', 'Le Cheddar', 'Le Comté', 'L''Emmental', 'B', 'Le Welsh est d''origine galloise mais est devenu LE plat des brasseries du Nord, toujours servi avec de la bière et du pain grillé !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Comment appelle-t-on le jet de harengs depuis le balcon de l''hôtel de ville de Dunkerque ?', 'La Criée', 'Le Lancer de harengs', 'Le Jet de harengs', 'La Pêche volante', 'C', 'Chaque année, le maire de Dunkerque jette des harengs fumés (des kippers) à la foule depuis le balcon de la mairie. C''est le moment le plus attendu du Carnaval !'),
('Patois', 'texte', NULL, 'Que signifie l''expression ch''ti « Cha va-ti ? » ?', 'Tu danses ?', 'Comment vas-tu ?', 'Tu manges ?', 'Tu travailles ?', 'B', '« Cha va-ti ? » est la façon ch''ti de dire « Comment vas-tu ? ». On peut répondre « Cha va, cha va ! » pour dire que tout va bien.'),
('Géographie', 'image', 'https://www.calaisxxl.com/wp-content/uploads/yatadata/PNAHDF000V508EW8/cap-blanc-nez-escalles-nohcab-20.jpg-compressed-1000x749.jpeg', 'Quel cap de la Côte d''Opale offre une vue sur les falaises d''Angleterre par temps clair ?', 'Le Cap Gris-Nez', 'Le Cap Blanc-Nez', 'Le Cap Hornu', 'Le Cap d''Alprech', 'B', 'Du haut du Cap Blanc-Nez (134 m), on peut voir les falaises de Douvres à 34 km. C''est le point le plus proche de l''Angleterre en France !'),
('Braderie de Lille', 'texte', NULL, 'Combien de kilomètres de stands la Braderie de Lille peut-elle atteindre ?', '50 km', '100 km', '150 km', '200 km', 'B', 'La Braderie de Lille, c''est environ 100 km de stands et 10 000 exposants ! Elle a lieu chaque premier week-end de septembre depuis le XIIe siècle.'),
('Histoire & Mines', 'image', 'https://hautsdefrance.media.tourinsoft.eu/upload/2022-06-17-pidz-56-web.jpg', 'Quel site minier du Nord-Pas-de-Calais est classé au patrimoine mondial de l''UNESCO ?', 'Le bassin minier entier', 'Uniquement la fosse de Lens', 'La mine de Bruay', 'Le terril de Loos-en-Gohelle', 'A', 'C''est l''ensemble du Bassin minier du Nord-Pas-de-Calais qui est classé UNESCO depuis 2012 : 353 éléments sur 120 km de long !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel est le surnom de la course cycliste Paris-Roubaix ?', 'La Reine des classiques', 'L''Enfer du Nord', 'Le Roi des pavés', 'La Folle du Nord', 'B', 'Paris-Roubaix est surnommée « L''Enfer du Nord » à cause de ses redoutables secteurs pavés, boueux et épuisants. La première édition date de 1896 !'),
('Célébrités du Nord', 'texte', NULL, 'Quel grand général né à Dunkerque est célèbre pour ses combats contre les Hollandais ?', 'Napoléon Bonaparte', 'Jean Bart', 'Le Maréchal Foch', 'Le Comte de Flandre', 'B', 'Jean Bart (1650-1702) est le plus célèbre corsaire dunkerquois. Il a sa statue sur la place éponyme et un hymne chanté à chaque Carnaval !'),
('Cinéma & Culture', 'image', 'https://proxymedia.woopic.com/api/v1/images/331%2FBIENVENUECHW0016337_BAN1_2424_NEWTV_HD.jpg', 'En quelle année est sorti le film « Bienvenue chez les Ch''tis » de Dany Boon ?', '2006', '2008', '2010', '2012', 'B', 'Le film a attiré plus de 20 millions de spectateurs en France, un record ! Il a été tourné principalement à Bergues, dans le Nord.'),
('Traditions & Folklore', 'image', 'https://www.douai.fr/sites/default/files/2022-12/adl_22-07-10_rigodon_006.jpg', 'Comment s''appelle la famille de géants qui défile dans les rues de Douai ?', 'Les Reuze', 'Les Gayant', 'Les Goliath', 'Les Grand''Jacques', 'B', 'La famille Gayant (Papa, Maman et les 3 enfants) défile à Douai depuis 1530. Gayant mesure 8,50 m et pèse 370 kg. La fête est classée par l''UNESCO !'),
('Gastronomie', 'texte', NULL, 'Quel fromage du Nord est célèbre pour son odeur particulièrement forte ?', 'Le Boulette d''Avesnes', 'Le Maroilles', 'Le Bergues', 'Le Vieux-Lille', 'B', 'Le Maroilles est fabriqué dans l''Avesnois depuis le VIIe siècle. Son odeur puissante cache un goût étonnamment doux et crémeux !'),
('Patois', 'audio', 'expression_biloute.mp3', 'Que signifie le terme ch''ti « Biloute » ?', 'Une frite', 'Un ami, un pote', 'Un ballon', 'Une bêtise', 'B', '« Biloute » est le terme d''affection ch''ti par excellence. Il signifie « petit gars » ou « mon pote » et s''utilise entre amis comme un signe de complicité.'),
('Géographie', 'texte', NULL, 'Quel est le plus haut terril d''Europe, situé à Loos-en-Gohelle ?', 'Le terril 42', 'Le terril du 11/19', 'Le terril de Pinchonvalles', 'Le terril de Rieulay', 'B', 'Les terrils jumeaux du 11/19 à Loos-en-Gohelle culminent à 186 m. Ils sont les plus hauts d''Europe et font partie du Bassin minier UNESCO !'),
('Carnaval de Dunkerque', 'audio', 'cantate_jean_bart.mp3', 'Quel hymne est chanté en chœur par la foule lors du Carnaval de Dunkerque ?', 'La Marseillaise du Nord', 'La Cantate à Jean Bart', 'L''Hymne des Flandres', 'Le Chant du Corsaire', 'B', 'La Cantate à Jean Bart est entonnée par des milliers de carnavaleux chaque année. C''est un moment d''émotion pure qui donne des frissons !'),
('Braderie de Lille', 'image', 'https://www.francebleu.fr/pikapi/images/b0d7721b-0c7f-4f7c-9903-1d9fd4af53ea/1200x680?webp=false', 'Quel est le plat traditionnel que l''on déguste en masse lors de la Braderie de Lille ?', 'Les carbonades flamandes', 'Les moules-frites', 'Le pot''je vleesch', 'La tarte au sucre', 'B', 'On estime que plus de 500 tonnes de moules sont consommées pendant la Braderie ! Les tas de coquilles vides devant les restaurants sont une vraie tradition.'),
('Histoire & Mines', 'texte', NULL, 'En quelle année a eu lieu la catastrophe minière de Courrières, la plus meurtrière d''Europe ?', '1896', '1906', '1916', '1926', 'B', 'L''explosion de la mine de Courrières le 10 mars 1906 a fait 1 099 morts. C''est la plus grande catastrophe minière d''Europe. Des rescapés sont remontés 20 jours après !'),
('Paris-Roubaix & Sport', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/vdn_864w/2023/04/13/node_1315450/56113174/public/2023/04/13/B9734006712Z.1_20230413005732_000%2BG1BMIGIK2.3-0.jpg?itok=Gc7w5owo1681374443', 'Quel secteur pavé mythique de Paris-Roubaix traverse une ancienne forêt minière ?', 'Le Carrefour de l''Arbre', 'La Trouée d''Arenberg', 'Le Mons-en-Pévèle', 'Le Pont Gibus', 'B', 'La Trouée d''Arenberg, longue de 2,4 km, est le passage le plus redouté de Paris-Roubaix. Les pavés y sont tellement défoncés qu''elle a été retirée du parcours en 2005 avant d''y revenir !'),
('Célébrités du Nord', 'texte', NULL, 'Quel président de la République française est né à Lille en 1890 ?', 'Raymond Poincaré', 'Charles de Gaulle', 'Georges Pompidou', 'Vincent Auriol', 'B', 'Charles de Gaulle est né au 9, rue Princesse à Lille le 22 novembre 1890. La maison natale est aujourd''hui un musée ouvert au public.'),
('Cinéma & Culture', 'texte', NULL, 'Dans « Bienvenue chez les Ch''tis », dans quelle ville est muté le personnage de Kad Merad ?', 'Dunkerque', 'Bergues', 'Bailleul', 'Cassel', 'B', 'Le film se déroule à Bergues, charmante petite ville fortifiée du Nord. Depuis le film, le tourisme y a explosé de 300% !'),
('Traditions & Folklore', 'texte', NULL, 'Comment appelle-t-on le masque et le costume porté par les participants du Carnaval de Dunkerque ?', 'Un déguisement de fête', 'Un clet''che', 'Un carnavalesque', 'Un masquelour', 'B', 'Le clet''che est l''ensemble masque + costume du Carnavaleux dunkerquois. Il permet de rester anonyme et de faire la fête sans être reconnu !'),
('Gastronomie', 'texte', NULL, 'Quelle est la particularité d''une « fricadelle » du Nord ?', 'Elle est à base de poisson', 'C''est une saucisse panée à base de viande hachée', 'Elle est toujours servie sucrée', 'C''est un dessert flamand', 'B', 'La fricadelle (ou fricandelle) est une saucisse panée à base de viande, indissociable du cornet de frites. C''est L''accompagnement roi de la baraque à frites !'),
('Patois', 'texte', NULL, 'Que signifie « Cha m''fait braire » en ch''ti ?', 'Ça me fait rire', 'Ça me fait pleurer', 'Ça me fait peur', 'Ça me fait mal', 'B', '« Braire » en ch''ti signifie « pleurer ». L''expression « Cha m''fait braire » s''utilise quand quelque chose vous rend triste ou vous fait de la peine.'),
('Géographie', 'image', 'https://www.teritoria.com/wp-content/uploads/2025/06/shutterstock_2373845287_cPascale-Gueret_-Lille-anciennes-maisons-du-centre-et-le-beffroi-de-la-Chambre-de-Commerce.jpg', 'Quelle est la hauteur du beffroi de l''Hôtel de Ville de Lille, le plus haut de la région ?', '76 m', '104 m', '87 m', '120 m', 'B', 'Le beffroi de l''Hôtel de Ville de Lille, construit entre 1924 et 1932, culmine à 104 m. C''est le plus haut beffroi civil de la région, classé UNESCO !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Comment appelle-t-on chaque jour de fête du Carnaval de Dunkerque ?', 'Un chahut', 'Une bande', 'Un cortège', 'Un défilé', 'B', 'Chaque « bande » est un défilé carnavalesque dans un quartier différent. Il y en a une quinzaine entre janvier et mars !'),
('Braderie de Lille', 'texte', NULL, 'Depuis quel siècle la Braderie de Lille existe-t-elle sous une forme ou une autre ?', 'Le Xe siècle', 'Le XIIe siècle', 'Le XVe siècle', 'Le XVIIIe siècle', 'B', 'Les premières traces de la Braderie remontent à 1127 ! Les serviteurs avaient le droit, un jour par an, de vendre les objets usagés de leurs maîtres.'),
('Histoire & Mines', 'texte', NULL, 'Quel métier dangereux consistait à détecter le grisou dans les galeries de mine ?', 'Le haveur', 'Le pénitent (ou canari humain)', 'Le galibot', 'Le porion', 'C', 'Le galibot était le jeune apprenti mineur, souvent âgé de 12 à 14 ans, qui descendait pour la première fois au fond. C''est aussi le nom d''une sculpture célèbre de Constantin Meunier.'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel est le trophée remis au vainqueur de Paris-Roubaix ?', 'Un maillot doré', 'Un pavé', 'Une coupe en cristal', 'Un casque de mineur', 'B', 'Le vainqueur de Paris-Roubaix reçoit un authentique pavé monté sur un socle. C''est le trophée le plus original du cyclisme !'),
('Célébrités du Nord', 'image', 'https://cdn-s-www.dna.fr/images/63DCBC3A-B2F9-4788-B1E3-E30307A41244/NW_raw/la-ch-tite-famille-de-dany-boon-avec-pierre-richard-valerie-bonneton-line-renaud-et-guy-lecluse-photo-dr-1518900945.jpg', 'Quel humoriste et acteur originaire d''Armentières a réalisé « Bienvenue chez les Ch''tis » ?', 'Franck Dubosc', 'Dany Boon', 'Kad Merad', 'Philippe Katerine', 'B', 'Dany Boon, né Daniel Hamidou à Armentières en 1966, est devenu le réalisateur du plus grand succès du cinéma français avec plus de 20 millions d''entrées !'),
('Cinéma & Culture', 'texte', NULL, 'Quel musée de Lens, ouvert en 2012, est une antenne du célèbre musée parisien ?', 'Le Centre Pompidou-Lens', 'Le Louvre-Lens', 'Le Musée d''Orsay-Lens', 'Le Grand Palais-Lens', 'B', 'Le Louvre-Lens a été construit sur un ancien carreau de mine. Son architecture de verre et d''aluminium par SANAA a redonné vie à tout un territoire !'),
('Traditions & Folklore', 'audio', 'chant_p_tit_quinquin.mp3', 'Quelle célèbre berceuse ch''ti raconte l''histoire d''une dentellière qui calme son bébé ?', 'L''Canchon dormoire', 'Le P''tit Quinquin', 'La Complainte du mineur', 'Dors min p''tit garchon', 'B', 'Le P''tit Quinquin, écrit par Alexandre Desrousseaux en 1853, est l''hymne officieux de Lille. « Quinquin » signifie « petit enfant » en ch''ti.'),
('Gastronomie', 'image', 'https://www.chezandre.fr/wp-content/uploads/2021/11/Carbonnade-Flamande.jpg', 'Quel alcool entre dans la recette traditionnelle de la carbonade flamande ?', 'Du vin rouge', 'De la bière brune', 'Du cidre', 'Du genièvre', 'B', 'La carbonade flamande est un ragoût de bœuf mijoté à la bière brune, au pain d''épices et à la cassonade. Le mariage sucré-salé est sa signature !'),
('Patois', 'texte', NULL, 'Que veut dire « Ej sus d''éch Nord » en picard ?', 'Je suis fatigué', 'Je suis du Nord', 'Je suis en retard', 'Je suis content', 'B', 'La phrase « Ej sus d''éch Nord » signifie simplement « Je suis du Nord ». Le picard est une langue à part entière, reconnue comme langue régionale !'),
('Géographie', 'texte', NULL, 'Quelle baie des Hauts-de-France est l''une des plus grandes d''Europe et classée Grand Site de France ?', 'La baie de Dunkerque', 'La baie de Somme', 'La baie d''Authie', 'La baie de Wissant', 'B', 'La baie de Somme couvre 70 km². On peut y observer des phoques et assister au spectacle des grandes marées. C''est aussi une étape migratoire pour des milliers d''oiseaux !'),
('Carnaval de Dunkerque', 'image', 'https://www.francebleu.fr/pikapi/images/fe0bfc96-9d72-4e2d-8697-09ef6781d807/1280?webp=false', 'Quel chapeau folklorique portent souvent les carnavaleux dunkerquois ?', 'Un haut-de-forme', 'Un chapeau melon ou un bicorne', 'Une casquette plate', 'Un béret basque', 'B', 'Le chapeau est un élément clé du clet''che. On voit souvent des chapeaux melons, des hauts-de-forme customisés ou des bicornes de corsaires en hommage à Jean Bart !'),
('Braderie de Lille', 'texte', NULL, 'Quel type d''objets vend-on traditionnellement à la Braderie de Lille ?', 'Des vêtements neufs uniquement', 'Des objets d''occasion et antiquités', 'De la nourriture exclusivement', 'Des œuvres d''art contemporain', 'B', 'À l''origine, la Braderie était un gigantesque vide-grenier. Même si aujourd''hui les stands professionnels sont nombreux, les chineurs trouvent toujours leur bonheur !'),
('Histoire & Mines', 'image', 'https://upload.wikimedia.org/wikipedia/commons/3/36/Lampe_de_mineur_Wolf_-_M_379-440_-_01.jpg', 'Comment s''appelle la lampe de sécurité inventée pour éviter les explosions de grisou dans les mines ?', 'La lampe de Davy', 'La lampe à huile', 'La bougie de mine', 'La lampe de Pasteur', 'A', 'La lampe Davy, inventée en 1815 par Humphry Davy, emprisonne la flamme dans un grillage métallique pour éviter d''enflammer le grisou. Elle a sauvé des milliers de vies !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel célèbre club de basket-ball du Nord a évolué dans la mythique salle Sportica ?', 'ESSM Le Portel', 'BCM Gravelines-Dunkerque', 'Lille Métropole Basket', 'Saint-Amand Hainaut Basket', 'B', 'Le BCM Gravelines-Dunkerque est l''un des clubs phares du championnat de France de basket. Sa salle historique, Sportica, a hélas été ravagée par un incendie fin 2023.'),
('Célébrités du Nord', 'texte', NULL, 'Quel grand peintre est né à Valenciennes en 1684 et est considéré comme le maître des fêtes galantes ?', 'Eugène Delacroix', 'Antoine Watteau', 'Jean-Honoré Fragonard', 'Nicolas Poussin', 'B', 'Antoine Watteau, né à Valenciennes, a inventé le genre des « fêtes galantes » en peinture. Son chef-d''œuvre « L''Embarquement pour Cythère » est au Louvre.'),
('Cinéma & Culture', 'texte', NULL, 'Quel festival de cinéma se tient chaque année à Arras ?', 'Le Festival du Film d''Animation d''Arras', 'L''Arras Film Festival', 'Le Festival Lumière d''Arras', 'Les Rencontres Cinématographiques d''Arras', 'B', 'L''Arras Film Festival est devenu un rendez-vous incontournable du cinéma européen, avec des avant-premières et des rencontres avec les réalisateurs.'),
('Traditions & Folklore', 'texte', NULL, 'Comment s''appelle la fête des géants dans le Nord, classée par l''UNESCO ?', 'La Ducasse', 'Les Fêtes de Gayant', 'La Kermesse aux géants', 'Le Grand Cortège', 'B', 'Les Fêtes de Gayant à Douai ont lieu chaque année en juillet. Elles sont inscrites au patrimoine culturel immatériel de l''humanité par l''UNESCO depuis 2005 !'),
('Gastronomie', 'texte', NULL, 'Quelle boisson alcoolisée à base de baies de genévrier est une spécialité du Nord ?', 'Le calvados', 'Le genièvre', 'L''absinthe', 'Le pommeau', 'B', 'Le genièvre (ou « jenever ») est l''eau-de-vie traditionnelle du Nord et de la Flandre. Il se boit en « bistouille » : mélangé au café !'),
('Patois', 'texte', NULL, 'Comment dit-on « manger » en ch''ti ?', 'Bouffer', 'Minger', 'Boustifailler', 'Grailler', 'B', '« Minger » est le verbe ch''ti pour « manger ». On dit « Viens minger ! » pour inviter quelqu''un à table. C''est un mot que vous entendrez dans toutes les familles du Nord !'),
('Géographie', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/ena_16_9_extra_big/2025/08/09/node_1613854/65107788/public/2025/08/09/46600502.jpeg?itok=RiozxHcr1754762682', 'Quel beffroi du Nord a inspiré Victor Hugo, qui le trouvait « admirable » ?', 'Le beffroi de Lille', 'Le beffroi de Douai', 'Le beffroi d''Arras', 'Le beffroi de Calais', 'B', 'Le beffroi de Douai, construit au XIVe siècle, abrite un carillon de 62 cloches. Victor Hugo l''a décrit avec admiration dans ses carnets de voyage en 1837.'),
('Carnaval de Dunkerque', 'texte', NULL, 'Combien de temps dure environ la saison du Carnaval de Dunkerque ?', 'Un week-end', 'Environ 3 mois (janvier à mars)', 'Une semaine', 'Deux jours', 'B', 'Le Carnaval de Dunkerque s''étend de janvier à mars avec une quinzaine de bandes dans les différents quartiers. C''est le plus long carnaval de France !'),
('Braderie de Lille', 'image', 'https://www.braderie-de-lille.fr/wp-content/uploads/2019/04/braderie-de-lille-fond-de-site-1024x579.jpg', 'Combien de visiteurs la Braderie de Lille attire-t-elle en un week-end ?', '500 000', '1 million', '2 à 3 millions', '5 millions', 'C', 'La Braderie de Lille attire entre 2 et 3 millions de visiteurs en un seul week-end ! C''est le plus grand marché aux puces d''Europe.'),
('Histoire & Mines', 'texte', NULL, 'Qu''est-ce qu''un « coron » dans le Nord ?', 'Un terril de mine', 'Une rangée de maisons ouvrières de mineurs', 'Un outil de mineur', 'Un puits de mine', 'B', 'Les corons sont des alignements de maisons identiques construites par les compagnies minières pour loger les familles de mineurs. Pierre Bachelet les a immortalisés en chanson !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel est le vélodrome mythique où se termine Paris-Roubaix ?', 'Le Vélodrome de Roubaix', 'Le Stade Vélodrome de Marseille', 'Le Vélodrome de Vincennes', 'Le Vélodrome de Saint-Quentin', 'A', 'Le vélodrome André-Pétrieux de Roubaix, ouvert en 1895, est le théâtre de l''arrivée de Paris-Roubaix. Les coureurs y font un dernier tour de piste devant un public en délire !'),
('Célébrités du Nord', 'image', 'https://upload.wikimedia.org/wikipedia/commons/1/15/Marguerite_Yourcenar-Bailleul-1982.10.04.Bernhard_De_Grendel_%2811%29.jpg', 'Quelle écrivaine née à Bruxelles mais originaire d''une famille lilloise fut la première femme élue à l''Académie française ?', 'Simone de Beauvoir', 'Marguerite Yourcenar', 'Colette', 'Marguerite Duras', 'B', 'Marguerite Yourcenar, née Marguerite de Crayencour, est issue d''une famille de Lille. Élue à l''Académie française en 1980, c''est la première femme à y siéger !'),
('Cinéma & Culture', 'audio', 'extrait_quand_la_mer_monte.mp3', 'Quel film de et avec Yolande Moreau, sorti en 2004, se déroule dans le Nord ?', 'Quand la mer monte...', 'Les Deschiens : le film', 'Chez nous', 'Henri', 'A', 'Yolande Moreau, originaire de Bruxelles mais adoptée par le Nord, a remporté le César de la meilleure première œuvre pour ce film tourné entre Dunkerque et la Côte d''Opale.');
INSERT INTO questions (theme, type_media, url_media, question, reponse_A, reponse_B, reponse_C, reponse_D, bonne_reponse, anecdote) VALUES
('Gastronomie', 'texte', NULL, 'Qu''est-ce qu''une « bistouille » dans le Nord ?', 'Une soupe de poisson', 'Un café arrosé de genièvre', 'Un dessert au spéculoos', 'Une bière artisanale', 'B', 'La bistouille, c''est le café du mineur : un café chaud allongé d''une rasade de genièvre. Un remontant légendaire pour affronter le froid du Nord !'),
('Patois', 'texte', NULL, 'Que signifie « un poco » en ch''ti ?', 'Un poisson', 'Un baiser', 'Un peu', 'Un copain', 'C', 'En ch''ti, « un poco » signifie « un peu ». On dit « Attends un poco ! » pour « Attends un peu ! ». Le ch''ti a conservé beaucoup d''emprunts aux langues latines.'),
('Carnaval de Dunkerque', 'texte', NULL, 'Comment s''appelle le premier jour du Carnaval de Dunkerque ?', 'La Bande de la Citadelle', 'Le Bal du Chat Noir', 'La Bande de Dunkerque', 'Le jour de Jean Bart', 'A', 'La Bande de la Citadelle ouvre traditionnellement la saison carnavalesque en janvier. C''est souvent la plus intime et la plus « roots » des bandes !'),
('Géographie', 'texte', NULL, 'Quelle est la sous-préfecture la plus au nord de la France ?', 'Boulogne-sur-Mer', 'Calais', 'Dunkerque', 'Hazebrouck', 'C', 'Dunkerque est la ville la plus septentrionale de France. Elle est plus au nord que certaines villes anglaises comme Londres !'),
('Braderie de Lille', 'texte', NULL, 'Comment appelle-t-on les brocanteurs qui exposent à la Braderie de Lille ?', 'Les chineurs', 'Les bradeux', 'Les puces', 'Les forains', 'B', 'Les « bradeux » sont les exposants de la Braderie. Certains arrivent la veille pour réserver leur emplacement et dorment sur place !'),
('Histoire & Mines', 'image', 'https://bassinminier-patrimoinemondial.org/wp-content/uploads/2014/11/75.jpg', 'Comment appelle-t-on la structure métallique au-dessus d''un puits de mine ?', 'Le derrick', 'Le chevalement', 'Le gaillard', 'Le pylône minier', 'B', 'Le chevalement est la tour métallique qui supporte les câbles de la cage d''ascenseur. Certains chevalements du Nord sont classés monuments historiques.'),
('Paris-Roubaix & Sport', 'image', 'https://www.lequipe.fr/_medias/img-photo-jpg/le-velodrome-de-roubaix-b-papon-l-equipe/1500000001550742/0:0,1997:1120-828-465-75/6f1e9.jpg', 'Quel est le nom officiel du vélodrome de Roubaix ?', 'Vélodrome Jean Stablinski', 'Vélodrome André-Pétrieux', 'Vélodrome Jacques Anquetil', 'Vélodrome Louison Bobet', 'B', 'Le vélodrome André-Pétrieux de Roubaix accueille l''arrivée de Paris-Roubaix depuis 1943. C''est un lieu mythique du cyclisme mondial !'),
('Célébrités du Nord', 'texte', NULL, 'Quel chanteur originaire de Lens a interprété « Les Corons » ?', 'Enrico Macias', 'Pierre Bachelet', 'Daniel Guichard', 'Michel Sardou', 'B', 'Pierre Bachelet (1944-2005) a fait pleurer des millions de Nordistes avec « Les Corons » en 1982. Cette chanson est devenue l''hymne non officiel du bassin minier !'),
('Cinéma & Culture', 'image', 'https://woody.cloudly.space/app/uploads/lille-tourisme/2023/11/thumbs/Musee-La-Piscine-Laurent-JAVOY-9-min-1920x960-crop-1699000875.jpg', 'Quel ancien bâtiment Art déco de Roubaix a été transformé en musée d''art et d''industrie ?', 'L''ancienne gare', 'La Piscine', 'L''usine textile', 'Le grand magasin', 'B', 'La Piscine de Roubaix, construite en 1932, a été reconvertie en musée en 2001. Son bassin central, entouré de sculptures, est spectaculaire !'),
('Traditions & Folklore', 'image', 'https://img.over-blog-kiwi.com/1/39/33/15/20150701/ob_1ba3bb_img-8623.jpg', 'Comment s''appellent les deux géants emblématiques de Dunkerque ?', 'Colas et Jacqueline', 'Reuze-Papa et Reuze-Maman', 'Jean et Marie', 'Flandrin et Flandrine', 'B', 'Le Reuze-Papa mesure 6,25 m et le Reuze-Maman 5,50 m. Ils sont portés par 6 personnes chacun et dansent à travers les rues de Dunkerque depuis 1862 !'),
('Gastronomie', 'image', 'https://www.ca-drache.fr/wp-content/uploads/2014/02/0a02dd00daea2f95221dfdc81ab6e8df.jpg', 'Quelle pâtisserie du Nord est faite de pâte briochée recouverte de cassonade et de crème ?', 'La tarte au Maroilles', 'La tarte au sucre', 'La gaufre fourrée', 'Le cramique', 'B', 'La tarte au sucre (ou « tarte à gros bords ») est un classique des boulangeries du Nord. Elle se déguste tiède, saupoudrée généreusement de vergeoise brune !'),
('Patois', 'audio', 'expression_chtimi_drache.mp3', 'Que signifie « Il drache » en ch''ti ?', 'Il fait chaud', 'Il pleut très fort', 'Il neige', 'Il y a du vent', 'B', '« Il drache » (ou « i drache ») signifie « il pleut des cordes ». Le mot « drache » viendrait du flamand. Dans le Nord, on connaît bien le phénomène !'),
('Géographie', 'texte', NULL, 'Quelle ville des Hauts-de-France est surnommée « la Venise du Nord » ?', 'Dunkerque', 'Saint-Omer', 'Amiens', 'Bergues', 'B', 'Saint-Omer, avec ses marais audomarois et ses canaux, est surnommée « la Venise du Nord ». On y cultive le chou-fleur en barque et on s''y promène en bacôve !'),
('Carnaval de Dunkerque', 'audio', 'musique_carnaval_fifres.mp3', 'Quel instrument de musique est typique des bandes du Carnaval de Dunkerque ?', 'L''accordéon', 'Le fifre et le tambour', 'La cornemuse', 'Le banjo', 'B', 'Les fifres et tambours sont au cœur de la musique carnavalesque dunkerquoise. Le rythme obsédant des tambours met la foule en transe !'),
('Braderie de Lille', 'image', 'https://www.lepoint.fr/resizer/v2/RJBZ56AD4FPVROCW75XG7YHGTY.jpg?auth=74b688ebbca5afe60699d19cd3e3d2b10d89077223f718a226751a728e04bcd4&width=765&height=575&smart=true', 'Que font traditionnellement les restaurateurs avec les coquilles de moules vides pendant la Braderie ?', 'Ils les recyclent immédiatement', 'Ils les empilent devant leur restaurant', 'Ils les jettent dans la Deûle', 'Ils les offrent aux passants', 'B', 'Les montagnes de coquilles de moules devant les restaurants sont une image iconique de la Braderie. Les restaurateurs rivalisent pour avoir le plus gros tas !'),
('Histoire & Mines', 'texte', NULL, 'Quel roman d''Émile Zola décrit les conditions de vie des mineurs du Nord ?', 'L''Assommoir', 'Germinal', 'La Terre', 'Au Bonheur des Dames', 'B', 'Germinal, publié en 1885, est le roman le plus célèbre sur les mines du Nord. Zola a passé deux mois à Anzin et Denain pour enquêter sur place !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel club de football du Nord a remporté le dernier titre de champion de France de Ligue 1 pour la région en 2021 ?', 'Le RC Lens', 'Le LOSC Lille', 'Le Valenciennes FC', 'L''US Boulogne', 'B', 'Le LOSC a été champion de France en 2021, 10 ans après son dernier titre. L''entraîneur Christophe Galtier et le buteur Burak Yilmaz ont porté l''équipe vers un titre historique !'),
('Célébrités du Nord', 'texte', NULL, 'Quel couturier né à Valenciennes a fondé une célèbre maison de haute couture parisienne ?', 'Christian Dior', 'Jean-Charles de Castelbajac', 'Pierre Cardin', 'Emanuel Ungaro', 'B', 'Jean-Charles de Castelbajac, né à Casablanca mais élevé dans le Nord, est un créateur emblématique connu pour son style pop et coloré !'),
('Cinéma & Culture', 'texte', NULL, 'Quelle phrase culte du film « Bienvenue chez les Ch''tis » est devenue un phénomène ?', '« Il fait beau dans le Nord ! »', '« Quand on vient dans le Nord, on braille deux fois »', '« Ch''est du Nord, biloute ! »', '« Hein ? Comment cha va ? »', 'B', 'La réplique complète est : « Quand on arrive dans le Nord, on braille deux fois : une fois quand on arrive, une fois quand on repart ». Elle est devenue un slogan régional !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce qu''une « ducasse » dans le Nord ?', 'Un marché aux puces', 'Une fête foraine de village', 'Un repas de famille', 'Un match de football', 'B', 'La ducasse est la fête patronale du village, avec manèges, stands de tir, baraques à frites et bal populaire. Chaque commune du Nord a sa ducasse !'),
('Gastronomie', 'texte', NULL, 'Quel type de frites est traditionnel dans les baraques à frites du Nord ?', 'Des frites surgelées', 'Des frites cuites deux fois dans de la graisse de bœuf', 'Des frites au four', 'Des frites de patate douce', 'B', 'La vraie frite du Nord est coupée fraîche, blanchie une première fois à basse température, puis recuite à haute température dans de la graisse de bœuf (le « blanc de bœuf »). Ça change tout !'),
('Patois', 'texte', NULL, 'Que veut dire « À tantôt ! » dans le Nord ?', 'À demain !', 'À tout à l''heure !', 'Au revoir pour toujours !', 'Bonne nuit !', 'B', '« À tantôt ! » est une expression très courante dans le Nord qui signifie « À tout à l''heure » ou « À plus tard ». Elle est utilisée quotidiennement, même par les non-ch''tiphones !'),
('Géographie', 'image', 'https://soandbia.com/wp-content/uploads/2022/04/DSC01176.jpg', 'Comment appelle-t-on le site naturel entre le Cap Blanc-Nez et le Cap Gris-Nez ?', 'La Côte Sauvage', 'Le Grand Site des Deux-Caps', 'Le Parc des Falaises', 'La Route du Littoral', 'B', 'Le Grand Site des Deux-Caps est labellisé « Grand Site de France ». Ses falaises de craie et d''argile offrent des panoramas à couper le souffle sur le détroit du Pas-de-Calais !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Que sont les « chapelles » dans le contexte du Carnaval de Dunkerque ?', 'Des églises décorées', 'Des maisons ou appartements où les carnavaleux font la fête', 'Des chars allégoriques', 'Des fanfares de quartier', 'B', 'Les « chapelles » sont des lieux privés (maisons, garages, caves) où les carnavaleux se retrouvent pour chanter, danser et boire entre les bandes. C''est un réseau secret et convivial !'),
('Braderie de Lille', 'texte', NULL, 'Comment s''appelle la course à pied qui a lieu le matin de la Braderie de Lille ?', 'Le Marathon de Lille', 'La Semi-Braderie', 'La Course de la Braderie', 'Les Foulées de la Braderie', 'C', 'La Course de la Braderie démarre tôt le samedi matin sur un parcours de 10 km à travers la ville. Les coureurs slaloment entre les stands qui s''installent !'),
('Histoire & Mines', 'image', 'https://woody.cloudly.space/app/uploads/douai/2020/05/thumbs/centre-historique-minier-lewarde-e-watteau-04-1920x960-crop-1603742830.jpg', 'Quel est le plus grand musée de la mine en France, situé à Lewarde ?', 'Le Musée de la Mine de Saint-Étienne', 'Le Centre Historique Minier de Lewarde', 'Le Musée du Charbon de Lens', 'Le Parc Minier de Bruay', 'B', 'Le Centre Historique Minier de Lewarde, installé dans l''ancienne fosse Delloye, accueille 150 000 visiteurs par an. On y descend dans des galeries reconstituées !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quelle célèbre course annuelle de moto sur sable réunit des milliers de pilotes sur la Côte d''Opale ?', 'L''Enduro du Touquet', 'Le Moto-Cross de Cassel', 'La Ronde des Sables', 'Le Beach-Cross de Berck', 'A', 'Créé en 1975 par Thierry Sabine, l''Enduropale du Touquet est la plus grande course de motos sur sable au monde, avec un départ spectaculaire sur la plage !'),
('Célébrités du Nord', 'image', 'https://www.charles-de-gaulle.org/wp-content/uploads/2021/06/2_ca-MNCDG_01_12_2020-26-bis-scaled.jpg', 'Que peut-on visiter au 9, rue Princesse à Lille ?', 'Le musée des Beaux-Arts', 'La maison natale de Charles de Gaulle', 'L''atelier de Watteau', 'La bibliothèque de Marguerite Yourcenar', 'B', 'La maison natale de Charles de Gaulle est un musée qui retrace l''enfance du Général. On y découvre la vie bourgeoise lilloise de la fin du XIXe siècle.'),
('Cinéma & Culture', 'texte', NULL, 'Quel film de Bruno Dumont, sorti en 2014, se déroule sur la Côte d''Opale ?', 'La Vie de Jésus', 'P''tit Quinquin', 'Hors Satan', 'L''Humanité', 'B', 'P''tit Quinquin est une mini-série/film policier hilarant et décalé de Bruno Dumont, tournée dans le Boulonnais. Le commandant Van der Weyden est devenu un personnage culte !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce que le « jeu de bourle » (ou boule flamande) pratiqué dans le Nord ?', 'Un jeu de cartes', 'Un jeu de boules traditionnel joué en salle', 'Un jeu de fléchettes', 'Un combat de coqs', 'B', 'La bourle est un jeu de boules typiquement flamand, joué dans un bourloire (salle dédiée). Les boules en bois sont aplaties d''un côté pour les faire courber !'),
('Gastronomie', 'image', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQaQTzWTs1dWJtkKYjZWzXyIAhehCixQHRzkA&s', 'Quelle spécialité sucrée lilloise est fourrée à la vergeoise et à la vanille ?', 'Le merveilleux', 'La gaufre fourrée lilloise', 'La tarte au sucre', 'Le spéculoos', 'B', 'La gaufre fourrée lilloise est molle et tiède, garnie d''un fourrage à la vergeoise, au beurre et à la vanille. Rien à voir avec les gaufres belges croustillantes !'),
('Patois', 'texte', NULL, 'Comment dit-on « la maison » en ch''ti ?', 'L''ostau', 'Éch mason', 'Éch baraque', 'L''mason', 'D', 'En ch''ti, on dit « l''mason » ou « el''mason » pour « la maison ». Le « l'' » remplace souvent « la » et le « ch'' » remplace « c'' » ou « ce ».'),
('Géographie', 'texte', NULL, 'Quelle ville fortifiée par Vauban, située dans le Nord, est classée au patrimoine mondial de l''UNESCO ?', 'Lille', 'Bergues', 'Le Quesnoy', 'Gravelines', 'A', 'La citadelle de Lille, construite par Vauban entre 1667 et 1670, est surnommée la « Reine des citadelles ». Elle fait partie des sites Vauban classés UNESCO !'),
('Carnaval de Dunkerque', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/vdn_864w/2023/02/18/node_1293191/55946206/public/2023/02/18/B9733516658Z.1_20230218143829_000%2BGLHM8BFLH.1-0.jpg?itok=WaAuQU6J1676793522', 'Quel cri de ralliement est poussé par les carnavaleux pour se retrouver dans la foule ?', '« Vive Jean Bart ! »', '« Et les copains d''abord ! »', '« Allez biloute ! »', '« Olé, olé, olé ! »', 'A', '« Vive Jean Bart ! » est le cri emblématique du Carnaval. Il est repris en chœur par des milliers de voix et résonne dans toute la ville !'),
('Braderie de Lille', 'texte', NULL, 'En quelle année la Braderie de Lille a-t-elle été annulée pour la première fois de son histoire moderne pour des raisons de sécurité ?', '2001', '2012', '2016', '2020', 'C', 'La Braderie a été annulée en 2016 suite aux attentats de Nice, par mesure de sécurité, puis en 2020-2021 à cause du Covid. Des annulations historiques !'),
('Histoire & Mines', 'texte', NULL, 'Comment appelle-t-on le chef d''équipe dans une mine du Nord ?', 'Le haveur', 'Le porion', 'Le galibot', 'Le mineur de fond', 'B', 'Le porion est le contremaître qui dirige les équipes de mineurs au fond. C''est lui qui répartit le travail et veille à la sécurité dans les galeries.'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Lors de quel événement festif annuel des milliers de coureurs à pied relient-ils les grandes villes du bassin minier ?', 'Le Marathon de la Deûle', 'La Route du Louvre', 'Les Foulées des Corons', 'Le Trail des Terrils', 'B', 'La Route du Louvre est un événement mythique qui mêle sport et patrimoine, reliant traditionnellement Lille (ou d''autres pôles) au musée du Louvre-Lens.'),
('Célébrités du Nord', 'texte', NULL, 'Quel photographe et réalisateur lensois est connu pour ses portraits de la vie quotidienne dans le bassin minier ?', 'Henri Cartier-Bresson', 'Willy Ronis', 'Raymond Depardon', 'Dominique Viger', 'D', 'Dominique Viger a documenté pendant des décennies la vie des cités minières du Pas-de-Calais, capturant la dignité et la chaleur humaine de ces communautés.'),
('Cinéma & Culture', 'image', 'https://www.patrimoine-environnement.fr/wp-content/uploads/2017/11/louvre-lens.jpg', 'Quel architecte japonais a conçu le bâtiment du Louvre-Lens ?', 'Tadao Ando', 'SANAA (Kazuyo Sejima)', 'Kengo Kuma', 'Toyo Ito', 'B', 'L''agence SANAA, dirigée par Kazuyo Sejima et Ryue Nishizawa (Prix Pritzker 2010), a conçu un bâtiment d''aluminium et de verre, léger comme un nuage posé sur la mine !'),
('Traditions & Folklore', 'texte', NULL, 'Que sont les « combats de coqs » dans la tradition nordiste ?', 'Un sport interdit partout en France', 'Un spectacle traditionnel encore toléré dans certains gallodromes du Nord', 'Un jeu de cartes', 'Une danse folklorique', 'B', 'Les combats de coqs sont une tradition controversée mais légalement tolérée dans les gallodromes du Nord par « tradition ininterrompue ». C''est l''une des rares exceptions en France.'),
('Gastronomie', 'texte', NULL, 'Quelle bière trappiste est brassée dans l''abbaye du Mont des Cats près de Bailleul ?', 'La Chimay', 'La Mont des Cats', 'L''Orval', 'La Westmalle', 'B', 'La bière du Mont des Cats est brassée en collaboration avec les moines de l''abbaye. C''est une ambrée douce et chaleureuse, parfaite compagne des fromages du Nord !'),
('Patois', 'audio', 'expression_vindiou.mp3', 'Que signifie le juron ch''ti « Vindiou ! » ?', 'Bravo !', 'Mon Dieu ! (expression de surprise)', 'Au revoir !', 'Attention !', 'B', '« Vindiou ! » est une déformation de « Vain Dieu ! » (ou « Vin Dieu ! »). C''est l''exclamation ch''ti par excellence pour exprimer la surprise ou l''agacement !'),
('Géographie', 'image', 'https://www.nausicaa.fr/sites/default/files/node/article/2023-06/Wissant-%C2%A9-Eric-Desaunois-Les-Deux-Caps.jpg', 'Quelle plage de la Côte d''Opale est prisée des amateurs de char à voile ?', 'La plage de Berck', 'La plage de Wissant', 'La plage de Dunkerque', 'La plage du Touquet', 'B', 'Wissant, entre les deux caps, est un spot légendaire de char à voile grâce à sa plage immense et ses vents puissants. Des championnats du monde y ont été organisés !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Comment appelle-t-on le maquillage extravagant porté par les carnavaleux dunkerquois ?', 'Le fard', 'Le grimage', 'L''intrigant', 'Le clown', 'B', 'Le grimage est l''art de se maquiller de façon outrancière pour le Carnaval. Les hommes se grimment en femmes, les femmes en hommes, tous dans la plus totale liberté !'),
('Braderie de Lille', 'image', 'https://upload.wikimedia.org/wikipedia/commons/f/f8/Lille_vue_gd_place.JPG', 'Sur quelle place emblématique de Lille se concentre le cœur de la Braderie ?', 'La place Rihour', 'La Grand''Place', 'La place de la République', 'La place Philippe Lebon', 'B', 'La Grand''Place (officiellement place du Général-de-Gaulle) est le cœur battant de la Braderie. C''est là que se concentrent les brocanteurs les plus prestigieux !'),
('Histoire & Mines', 'texte', NULL, 'Comment appelle-t-on le wagonnet utilisé pour remonter le charbon du fond de la mine ?', 'La berline', 'La brouette de mine', 'Le tombereau', 'Le skip', 'A', 'La berline est le terme utilisé dans le Nord pour désigner le wagonnet de mine. Les galibots poussaient des dizaines de berlines chargées de charbon chaque jour !'),
('Paris-Roubaix & Sport', 'image', 'https://essm-basket.fr/wp-content/uploads/2021/10/chaudron-ambiance.jpg', 'Dans quelle ville côtière se trouve "Le Chaudron", la salle réputée incandescente de l''équipe de basket locale ?', 'Boulogne-sur-Mer', 'Le Portel', 'Calais', 'Dunkerque', 'B', 'L''ESSM Le Portel est célèbre pour son public exceptionnellement ferveur. Sa salle, surnommée "Le Chaudron", est l''une des enceintes les plus redoutées de la Pro A de basket !'),
('Célébrités du Nord', 'texte', NULL, 'Quelle chanteuse originaire de Dunkerque est connue pour « Dernière danse » ?', 'Aya Nakamura', 'Indila', 'Louane', 'Shy''m', 'B', 'Indila, de son vrai nom Adila Sedraïa, a grandi à Dunkerque. « Dernière danse » (2013) a dépassé le milliard de vues sur YouTube !'),
('Traditions & Folklore', 'audio', 'musique_geants_flandres.mp3', 'Comment appelle-t-on les processions de géants dans les Flandres ?', 'Les cavalcades', 'Les rondos des géants', 'Les cortèges de géants', 'Les reuzestoet', 'A', 'Les cavalcades de géants rythment la vie des villes flamandes du Nord. Chaque ville a son géant porteur d''identité : Gayant à Douai, les Reuze à Dunkerque, Lydéric à Lille...');
INSERT INTO questions (theme, type_media, url_media, question, reponse_A, reponse_B, reponse_C, reponse_D, bonne_reponse, anecdote) VALUES
('Gastronomie', 'texte', NULL, 'Qu''est-ce qu''un « cramique » dans le Nord ?', 'Un gâteau sec', 'Un pain brioché aux raisins secs', 'Une crêpe flamande', 'Un biscuit au genièvre', 'B', 'Le cramique est un pain brioché moelleux farci de raisins secs, typique de la Flandre. On le mange au goûter, tartiné de beurre demi-sel !'),
('Patois', 'texte', NULL, 'Que signifie « éne berdouille » en ch''ti ?', 'Une grosse bêtise', 'Un gros ventre', 'Une mauvaise journée', 'Un nid de poule', 'B', 'Une « berdouille » désigne un gros ventre en ch''ti. On dit « il a eine bonne berdouille » pour parler de quelqu''un qui a bien mangé !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Quel personnage historique les carnavaleux dunkerquois célèbrent-ils en héros ?', 'Louis XIV', 'Jean Bart', 'Napoléon', 'Vauban', 'B', 'Jean Bart, corsaire dunkerquois du XVIIe siècle, est le héros absolu de la ville. Sa statue trône sur la place éponyme et sa cantate est l''hymne du Carnaval !'),
('Géographie', 'image', 'https://www.pariszigzag.fr/wp-content/uploads/2025/03/cassel.webp', 'Quelle petite ville perchée sur un mont est surnommée le « balcon des Flandres » ?', 'Bailleul', 'Cassel', 'Wormhout', 'Hazebrouck', 'B', 'Cassel, perchée à 176 m sur le Mont Cassel, offre un panorama sur toute la plaine flamande. Philippe de France y a gagné une bataille en 1328 !'),
('Braderie de Lille', 'texte', NULL, 'Quel animal en céramique est le symbole de la ville de Lille, visible sur la Grand''Place ?', 'Un lion', 'Une déesse', 'Un coq', 'Un beffroi miniature', 'B', 'La Déesse, colonne érigée en 1845 sur la Grand''Place, commémore la résistance de Lille au siège autrichien de 1792. Elle est le symbole de la ville !'),
('Histoire & Mines', 'texte', NULL, 'Quel système de ventilation était crucial pour la survie des mineurs dans les galeries ?', 'Les éoliennes souterraines', 'L''aérage', 'La climatisation des mines', 'Les souffleries hydrauliques', 'B', 'L''aérage est le système de ventilation des galeries de mine. Sans lui, le grisou (méthane) s''accumulerait et provoquerait des explosions mortelles.'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel est le nom du secteur pavé le plus proche de l''arrivée à Roubaix ?', 'Le Carrefour de l''Arbre', 'L''Espace Charles Crupelandt', 'Le Pont Gibus', 'La Trouée d''Arenberg', 'A', 'Le Carrefour de l''Arbre est l''avant-dernier secteur pavé de Paris-Roubaix. C''est souvent là que la course se décide, à quelques kilomètres du vélodrome !'),
('Célébrités du Nord', 'texte', NULL, 'Quel mathématicien célèbre est né à Lille et a donné son nom à un théorème fondamental de l''algèbre ?', 'Blaise Pascal', 'Henri Poincaré', 'Joseph Bertrand', 'Charles Hermite', 'D', 'Charles Hermite, né à Dieuze (Lorraine) mais formé au lycée de Lille, a démontré la transcendance du nombre e. Son travail a révolutionné les mathématiques !'),
('Cinéma & Culture', 'image', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTt1B_fg8UGzf_ZEjikDaJ9sk0PvWirgCZoTQ&s', 'Quel aquarium géant de Boulogne-sur-Mer est le plus grand d''Europe ?', 'L''Océanopolis', 'Nausicaá', 'Sea Life', 'L''Aquarium de Paris', 'B', 'Nausicaá, le Centre National de la Mer, accueille plus de 58 000 animaux marins dans un bassin de 10 000 m³. C''est le plus grand aquarium d''Europe !'),
('Traditions & Folklore', 'texte', NULL, 'Comment s''appelle la tradition de « jeter l''arbre de Noël » par la fenêtre le 6 janvier dans certaines villes du Nord ?', 'La Bûche volante', 'Le Vol du Sapin', 'La Défenestration du sapin', 'La Sortie du sapin', 'C', 'Dans certaines villes du Nord, il est de tradition de jeter le sapin de Noël par la fenêtre le jour de l''Épiphanie, le 6 janvier. Une coutume surprenante !'),
('Gastronomie', 'image', 'https://www.ideemiam.com/upload/images/article/768x400/img_1960.jpg', 'Quelle spécialité fromagère de l''Avesnois est de forme conique et recouverte d''épices ?', 'Le Vieux-Lille', 'La Boulette d''Avesnes', 'Le Bergues', 'Le Mimolette vieille', 'B', 'La Boulette d''Avesnes est fabriquée à partir de Maroilles frais malaxé avec des herbes et épices. Sa croûte rouge paprika est sa signature !'),
('Patois', 'audio', 'expression_baraque_frites.mp3', 'Comment dit-on « une baraque à frites » en ch''ti ?', 'Eine friterie', 'Eine baraque à frites', 'Eine cabane à frittes', 'In cornet d''frites', 'B', 'La « baraque à frites » est un pilier de la culture du Nord. On en trouve à chaque coin de rue, et chaque famille a sa préférée !'),
('Géographie', 'texte', NULL, 'Quel fleuve traverse Lille ?', 'L''Escaut', 'La Deûle', 'La Lys', 'L''Aa', 'B', 'La Deûle traverse Lille et a joué un rôle crucial dans le développement industriel de la ville. Aujourd''hui, ses berges sont aménagées pour les promenades !'),
('Carnaval de Dunkerque', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/ena_16_9_extra_big/2020/02/27/node_716657/45528884/public/2020/02/27/B9722734203Z.1_20200227163258_000%2BGSKFK0BRV.1-0.jpg?itok=kpHl87Em1582880236', 'Quel accessoire inattendu est souvent porté par les carnavaleux malgré le thème festif ?', 'Un casque de viking', 'Un parapluie (pour la pluie du Nord !)', 'Un bouclier', 'Des raquettes de neige', 'B', 'Le parapluie au Carnaval de Dunkerque est un classique ! Il protège de la pluie nordiste mais aussi des harengs lancés depuis le balcon de la mairie.'),
('Braderie de Lille', 'texte', NULL, 'Quel est le record estimé de coquilles de moules empilées devant un restaurant lors de la Braderie ?', '2 mètres', '4 mètres', '6 mètres', '8 mètres', 'C', 'Certains restaurants atteignent des montagnes de coquilles de plus de 6 mètres de haut ! C''est un concours officieux très suivi par les habitués.'),
('Histoire & Mines', 'image', 'https://cloudfront-eu-central-1.images.arcpublishing.com/infopro/TYE7YM5HKJLYZH5E23TN5LILIU.jpg', 'Comment appelle-t-on les petits jardins ouvriers attenants aux maisons de mineurs ?', 'Les parterres', 'Les jardinets', 'Les carins', 'Les courées', 'B', 'Les jardinets des corons permettaient aux familles de mineurs de cultiver légumes et fleurs. C''est un héritage précieux de la culture minière du Nord !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'En plus du cyclisme, quel sport est historiquement lié au Nord avec de grands clubs ?', 'Le rugby', 'Le football', 'Le tennis', 'La natation', 'B', 'Le Nord est une terre de football ! Le LOSC, le RC Lens, Valenciennes et le Racing Club de Calais ont tous marqué l''histoire du foot français.'),
('Célébrités du Nord', 'image', 'https://i.ytimg.com/vi/p1z-B29Rfp0/maxresdefault.jpg', 'Quelle chanteuse née à Hénin-Beaumont a été révélée par « The Voice » en 2013 ?', 'Shy''m', 'Louane', 'Zaz', 'Indila', 'B', 'Louane Emera, née en 1996 à Hénin-Beaumont, a percé grâce à The Voice puis au film « La Famille Bélier ». Sa chanson « Avenir » est devenue un tube !'),
('Cinéma & Culture', 'texte', NULL, 'Quel grand musée des Beaux-Arts de Lille est l''un des plus importants de France ?', 'Le Musée d''Art Moderne', 'Le Palais des Beaux-Arts de Lille', 'Le LaM', 'Le Musée de la Chartreuse', 'B', 'Le Palais des Beaux-Arts de Lille est le deuxième musée de France après le Louvre par la richesse de ses collections : Rubens, Van Dyck, Goya, Delacroix...'),
('Traditions & Folklore', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/ena_16_9_extra_big/2017/07/27/node_197432/30432643/public/2017/07/27/B9712724475Z.1_20170727165138_000%2BGPG9G3GDD.2-0.jpg?itok=8lC8v6da1501183891', 'Comment s''appelle le géant fondateur légendaire de Lille ?', 'Gayant', 'Lydéric', 'Phinaert', 'Reuze', 'B', 'Selon la légende, Lydéric, orphelin élevé par un ermite, a vaincu le brigand Phinaert et fondé Lille au VIIe siècle. Lydéric et Phinaert sont les géants de Lille !'),
('Gastronomie', 'texte', NULL, 'Quelle sauce rouge typique accompagne souvent les frites dans le Nord ?', 'Le ketchup', 'La sauce « samouraï »', 'La harissa', 'La sauce tomate maison', 'B', 'La sauce samouraï (mayonnaise épicée au piment) est LA sauce tendance des baraques à frites du Nord. Incontournable avec un américain-frites !'),
('Patois', 'texte', NULL, 'Que veut dire « al''dégaine » en ch''ti ?', 'En cachette', 'Rapidement', 'Avec dégoût', 'En désordre', 'B', '« Al''dégaine » signifie « rapidement, en vitesse ». On dit « Viens al''dégaine ! » pour presser quelqu''un. C''est une expression très vivante dans le Nord !'),
('Géographie', 'image', 'https://bonaccueil-marais.fr/wp-content/uploads/2024/07/vue-du-ciel-marais-audomarois.webp', 'Comment s''appellent les embarcations traditionnelles des marais de Saint-Omer ?', 'Des barques plates', 'Des bacôves', 'Des gabarres', 'Des pirogues', 'B', 'Les bacôves sont les barques à fond plat utilisées dans les marais audomarois. Les maraîchers s''en servent encore pour cultiver et récolter leurs légumes !'),
('Carnaval de Dunkerque', 'texte', NULL, 'À quelle heure commence traditionnellement une bande de Carnaval à Dunkerque ?', 'À midi', 'À 15h', 'Le matin à 10h', 'Le soir à 20h', 'B', 'Les bandes démarrent généralement vers 15h et durent jusqu''au soir. Avant la bande, les carnavaleux se retrouvent dans les chapelles pour se préparer et chanter !'),
('Braderie de Lille', 'texte', NULL, 'Quel est le slogan officiel souvent associé à la Braderie de Lille ?', '« Bienvenue dans le Nord ! »', '« Tous à la Braderie ! »', '« La plus grande du monde ! »', '« Venez chiner à Lille ! »', 'B', 'Le slogan « Tous à la Braderie ! » est repris par la ville et les médias. La Braderie est le plus grand marché aux puces d''Europe !'),
('Histoire & Mines', 'texte', NULL, 'Quel oiseau était utilisé par les mineurs pour détecter le grisou dans les galeries ?', 'Le rossignol', 'Le canari', 'Le moineau', 'La tourterelle', 'B', 'Les canaris étaient emmenés dans les mines car ils sont très sensibles au grisou. Si le canari s''évanouissait, les mineurs savaient qu''il fallait évacuer !'),
('Paris-Roubaix & Sport', 'image', 'https://www.francebleu.fr/pikapi/images/02430344-bd8c-435b-a78d-53da3c3bbf4f/1200x680?webp=false', 'Quel stade mythique du Pas-de-Calais est surnommé « l''enfer de Bollaert » ?', 'Le stade Pierre-Mauroy', 'Le stade Bollaert-Delelis', 'Le stade du Hainaut', 'Le stade de la Libération', 'B', 'Le stade Bollaert-Delelis de Lens est l''un des plus chauds de France. Ses 38 000 places résonnent des chants des supporters lensois, réputés parmi les meilleurs !'),
('Célébrités du Nord', 'texte', NULL, 'Quel explorateur né à Boulogne-sur-Mer a navigué en Australie et en Tasmanie ?', 'La Pérouse', 'Nicolas Baudin', 'Jean-François de Galaup', 'Louis-Antoine de Bougainville', 'B', 'Nicolas Baudin, né à Saint-Martin-de-Ré mais parti de Boulogne, a exploré les côtes d''Australie en 1800-1803. Il a nommé de nombreux sites géographiques !'),
('Cinéma & Culture', 'audio', 'extrait_film_chez_nous.mp3', 'Quel film de Lucas Belvaux, sorti en 2017, traite de la montée du Front National dans le Nord ?', 'La Vie rêvée des anges', 'Chez nous', 'Raisons d''État', 'Pas de repos pour les braves', 'B', '« Chez nous », avec Émilie Dequenne, dépeint la vie d''une infirmière confrontée à la montée de l''extrême droite dans une ville minière du Pas-de-Calais.'),
('Traditions & Folklore', 'texte', NULL, 'Quel jeu traditionnel du Nord consiste à lancer des palets en fonte vers un but ?', 'Le jeu de fléchettes', 'Le jeu de javelot', 'Le jeu de boules', 'Le jeu de lancer de harengs', 'B', 'Le javelot (ou « tir au javelot ») est un jeu traditionnel du Nord où l''on lance des palets en fonte vers une cible. On y joue encore dans les estaminets !'),
('Gastronomie', 'image', 'https://img.lemde.fr/2011/07/18/4/0/575/383/1440/960/60/0/ill_1549916_226f_potjevleesch.jpg', 'Combien de viandes différentes entre dans la recette du Potjevleesch ?', '2 viandes', '3 viandes', '4 viandes', '5 viandes', 'C', 'Le Potjevleesch (« petit pot de viandes » en flamand) contient traditionnellement 4 viandes : poulet, lapin, veau et porc, cuites en gelée et servies froides !'),
('Patois', 'texte', NULL, 'Que signifie « Éch wassingue » en ch''ti ?', 'Un vent froid', 'Une serpillière', 'Un vêtement mouillé', 'Une pluie fine', 'B', 'La « wassingue » est le mot ch''ti pour la serpillière. C''est l''un des mots régionaux les plus connus, utilisé quotidiennement dans le Nord !'),
('Géographie', 'texte', NULL, 'Quel est le plus long fleuve côtier du Nord-Pas-de-Calais ?', 'La Lys', 'L''Aa', 'La Canche', 'L''Authie', 'B', 'L''Aa, long de 89 km, est un petit fleuve côtier emblématique du Nord. Son nom, le plus court de France, signifierait « eau » en celte !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Quelle est la bande la plus importante et la plus connue du Carnaval ?', 'La Bande de Malo', 'La Bande de Dunkerque (ou Bande de la Citadelle)', 'La Bande de Rosendaël', 'La Bande des Pêcheurs', 'B', 'La Bande de Dunkerque est la plus grande et la plus attendue, avec des milliers de participants. Elle se termine par le jet de harengs depuis la mairie !'),
('Braderie de Lille', 'image', 'https://asset-prod.france.fr/Que_faire_Lille_f14724966b.jpeg', 'Quel quartier historique de Lille est particulièrement animé pendant la Braderie ?', 'Le quartier Euralille', 'Le Vieux-Lille', 'Le quartier Wazemmes', 'Le quartier Moulins', 'B', 'Le Vieux-Lille, avec ses rues pavées et ses façades flamandes, est l''un des quartiers les plus prisés de la Braderie. Les antiquaires y sont particulièrement nombreux !'),
('Histoire & Mines', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/vdn_864w/2018/07/14/node_416597/39619719/public/2018/07/14/B9716321614Z.1_20180714104001_000%2BGG9BM636B.1-0.jpg?itok=jBtRNOA71531557613', 'Que représente la célèbre sculpture « Le Galibot » visible dans le bassin minier ?', 'Un ingénieur des mines', 'Un jeune apprenti mineur', 'Un chef de galerie', 'Un cheval de mine', 'B', 'Le Galibot est le jeune mineur, souvent un adolescent, qui descendait pour la première fois au fond. Les sculptures de galibots sont un hommage à ces enfants courageux.'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel matériau compose les fameux pavés de Paris-Roubaix ?', 'Le granit', 'Le grès', 'Le calcaire', 'Le basalte', 'B', 'Les pavés de Paris-Roubaix sont en grès, une roche locale très dure. Certains secteurs datent de l''époque napoléonienne et n''ont jamais été refaits !'),
('Célébrités du Nord', 'texte', NULL, 'Quel sculpteur originaire de Valenciennes a réalisé la colonne Vendôme à Paris ?', 'Rodin', 'Auguste Lemaire', 'Antoine-Denis Chaudet', 'Jean-Baptiste Carpeaux', 'D', 'Jean-Baptiste Carpeaux (1827-1875) est l''un des plus grands sculpteurs français. Né à Valenciennes, il a réalisé « La Danse » pour l''Opéra de Paris !'),
('Cinéma & Culture', 'texte', NULL, 'Quel grand événement culturel transforme Lille en capitale européenne chaque automne ?', 'Lille Art Fair', 'Lille3000', 'Les Nuits Secrètes', 'Le Festival de Lille', 'B', 'Lille3000, né de la dynamique de Lille 2004 (Capitale européenne de la culture), organise des expositions, événements et métamorphoses urbaines tous les 2-3 ans !'),
('Traditions & Folklore', 'texte', NULL, 'Comment appelle-t-on un estaminet dans le Nord ?', 'Un restaurant gastronomique', 'Un café-taverne traditionnel flamand', 'Une salle de spectacle', 'Un marché couvert', 'B', 'L''estaminet est le café-taverne traditionnel du Nord, où l''on joue aux jeux flamands, on boit de la bière et on mange des plats régionaux dans une ambiance chaleureuse !'),
('Gastronomie', 'audio', 'commande_baraque_frites.mp3', 'Que commande-t-on classiquement dans une baraque à frites du Nord en disant « un américain » ?', 'Un hamburger', 'Un sandwich baguette avec steak haché et frites', 'Un hot-dog à la moutarde', 'Un cornet de frites sauce ketchup', 'B', 'L''« américain » du Nord est un sandwich baguette garni de steak haché (ou fricadelle), frites et sauce. Rien à voir avec le hamburger américain !'),
('Patois', 'texte', NULL, 'Comment dit-on « il fait froid » en ch''ti ?', 'I fait frette', 'I fait frod', 'I glache', 'I caille deûr', 'B', '« I fait frod » est la façon ch''ti de dire « il fait froid ». Le « f » remplace souvent le « fr » français. On peut aussi entendre « i pèle » !'),
('Géographie', 'image', 'https://tourisme-lens.fr/content/uploads/2020/06/trails.jpg', 'De quoi sont principalement composés les terrils du Nord ?', 'De charbon pur', 'De schistes et résidus d''extraction', 'De terre végétale', 'De cendres industrielles', 'B', 'Les terrils sont des montagnes de schistes et de résidus de tri du charbon. Certains font plus de 100 m de haut. La nature y a repris ses droits avec une biodiversité étonnante !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Comment appelle-t-on le mardi qui clôture le Carnaval de Dunkerque ?', 'Le Mardi Gras', 'Le Mardi des Cendres', 'La Nuit des Intrigants', 'Le Grand Final', 'A', 'Le Mardi Gras est le point d''orgue du Carnaval de Dunkerque. C''est le jour de la Bande de Dunkerque et du célèbre jet de harengs, clôturant des semaines de fête !'),
('Histoire & Mines', 'texte', NULL, 'Comment s''appelle le cheval utilisé dans les mines du Nord pour tirer les berlines ?', 'Le destrier', 'Le cheval de mine (ou cheval de fond)', 'Le percheron minier', 'Le mulet de galerie', 'B', 'Les chevaux de mine passaient parfois leur vie entière au fond, sans jamais revoir la lumière du jour. Certains devenaient aveugles. Leur mémoire est honorée dans les musées.'),
('Cinéma & Culture', 'image', 'https://upload.wikimedia.org/wikipedia/fr/d/d5/Villa_Cavrois_Image_Facade_Sud.jpg', 'Quel chef-d''œuvre de l''architecture moderniste, conçu par Mallet-Stevens, se visite à Croix ?', 'La Villa Savoye', 'La Villa Cavrois', 'La Maison de Verre', 'La Cité Radieuse', 'B', 'La Villa Cavrois (1932), commandée par l''industriel Paul Cavrois, est un joyau Art déco/moderniste. Restaurée par le CMN, elle est ouverte au public depuis 2015 !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce que la « Saint-Nicolas » dans le Nord ?', 'Un simple jour férié', 'La fête où l''on offre des friandises aux enfants sages le 6 décembre', 'Un carnaval de printemps', 'Un marché de Noël', 'B', 'Dans le Nord, la Saint-Nicolas (6 décembre) est presque aussi importante que Noël ! Saint Nicolas apporte oranges, pains d''épices et chocolats aux enfants sages.');
INSERT INTO questions (theme, type_media, url_media, question, reponse_A, reponse_B, reponse_C, reponse_D, bonne_reponse, anecdote) VALUES
('Gastronomie', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/vdn_864w/2016/10/01/node_52910/5506327/public/2016/10/01/B979855854Z.1_20161001184447_000%2BGF37NC87A.2-0.jpg?itok=0tiswFF31475340327', 'Qu''est-ce qu''une « flamiche aux poireaux » ?', 'Une soupe de poireaux', 'Une tarte salée aux poireaux et crème', 'Un gratin de légumes', 'Une quiche lorraine', 'B', 'La flamiche aux poireaux est une tarte salée fondante typique de Picardie, garnie de poireaux fondus dans la crème fraîche et les œufs !'),
('Patois', 'texte', NULL, 'Que signifie « barouler » en ch''ti ?', 'Travailler dur', 'Se promener sans but', 'Tomber par terre', 'Chanter fort', 'B', '« Barouler » signifie se balader sans but précis. On dit « éj va barouler in ville » pour « je vais me promener en ville ». Une activité typiquement ch''ti !'),
('Carnaval de Dunkerque', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/ena_16_9_extra_big/2024/01/20/node_1421024/57424066/public/2024/01/20/10933903.jpeg?itok=kzYKs5No1705749365', 'Quel est le bal masqué le plus ancien et le plus prestigieux du Carnaval de Dunkerque ?', 'Le Bal de la Citadelle', 'Le Bal du Chat Noir', 'Le Bal du Corsaire', 'Le Bal des Flandres', 'B', 'Le Bal du Chat Noir date de 1899 et se tient au Kursaal. C''est le plus ancien et le plus prestigieux des bals du Carnaval, sur invitation uniquement !'),
('Géographie', 'texte', NULL, 'Quelle cathédrale gothique d''Amiens est la plus vaste de France ?', 'La cathédrale de Reims', 'La cathédrale Notre-Dame d''Amiens', 'La cathédrale de Beauvais', 'La cathédrale de Laon', 'B', 'La cathédrale Notre-Dame d''Amiens peut contenir deux fois Notre-Dame de Paris ! Avec ses 200 000 m³, c''est la plus vaste cathédrale gothique de France.'),
('Braderie de Lille', 'texte', NULL, 'Quel métro lillois dessert directement la Grand''Place pendant la Braderie ?', 'Le métro ligne 1', 'Le métro ligne 2', 'Les deux lignes', 'Il n''y a pas de métro à Lille', 'C', 'Le VAL (Véhicule Automatique Léger) de Lille a été le premier métro automatique du monde en 1983. Les deux lignes desservent le centre pendant la Braderie !'),
('Histoire & Mines', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/vdn_864w/2026/02/23/node_1677550/67468316/public/2026/02/23/64531387.jpeg?itok=fJY9EGiv1771939078', 'À quelle profondeur pouvaient descendre les mines les plus profondes du Nord ?', '200 mètres', '500 mètres', '1 000 mètres', '2 000 mètres', 'C', 'Certaines fosses du bassin minier atteignaient 1 000 m de profondeur ! La température y dépassait les 40°C et les conditions de travail étaient infernales.'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel coureur français a remporté Paris-Roubaix en solo en 2022 ?', 'Julian Alaphilippe', 'Dylan van Baarle', 'Christophe Laporte', 'Mathieu van der Poel', 'D', 'Mathieu van der Poel (néerlandais, pas français !) a gagné en solitaire en 2023. Le dernier vainqueur français est Gilbert Duclos-Lassalle en 1993 !'),
('Célébrités du Nord', 'texte', NULL, 'Quel chanteur, leader du groupe « La Chicane », est originaire du bassin minier ?', 'Renaud', 'Raoul de Godewarsvelde', 'Pierre Perret', 'Jacques Brel', 'B', 'Raoul de Godewarsvelde (1928-1977) est le chanteur ch''ti par excellence. Ses chansons célèbrent la vie dans le Nord avec humour et tendresse !'),
('Cinéma & Culture', 'texte', NULL, 'Quel film d''Érick Zonca, tourné dans le Nord, a remporté le César du meilleur film en 1999 ?', 'Chez nous', 'La Vie rêvée des anges', 'Germinal', 'Bienvenue chez les Ch''tis', 'B', '« La Vie rêvée des anges », tourné à Lille, raconte l''histoire de deux jeunes femmes en difficulté. Élodie Bouchez et Natacha Régnier y sont exceptionnelles !'),
('Traditions & Folklore', 'image', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQbScsxTF4chDCmJMpNC1mjFhdg-zoih1hoLQ&s', 'Quel jeu de fléchettes spécifique est pratiqué dans les estaminets du Nord ?', 'Le darts anglais', 'Les fléchettes traditionnelles (ou tir vertical)', 'Le jeu de 501', 'Les flèches de bar', 'B', 'Dans le Nord, on joue aux fléchettes verticalement, vers un plafond en liège ! C''est unique en France et on le pratique principalement dans les estaminets flamands.'),
('Gastronomie', 'texte', NULL, 'Qu''est-ce qu''un « merveilleux » en pâtisserie dans le Nord ?', 'Un éclair au chocolat', 'Un gâteau meringué recouvert de crème fouettée et copeaux de chocolat', 'Un croissant géant', 'Une tarte aux fruits rouges', 'B', 'Le merveilleux est un nuage de meringue, crème fouettée et copeaux de chocolat. Fred, pâtissier lillois, l''a remis au goût du jour et en a fait un empire !'),
('Patois', 'audio', 'expression_mi_chtimi.mp3', 'Que signifie « éch biau temps » en ch''ti ?', 'Le mauvais temps', 'Le beau temps', 'Le vieux temps', 'Le printemps', 'B', '« Éch biau temps » signifie « le beau temps ». En ch''ti, « biau » remplace « beau ». On dit souvent « i fait biau » pour « il fait beau », ce qui est rare dans le Nord !'),
('Géographie', 'image', 'https://www.somme-tourisme.com/assets/uploads/2024/09/somme-tourisme-la-tortuga-cathedrale-amiens-3.jpg', 'Combien de mètres fait la flèche de la cathédrale d''Amiens ?', '90 m', '112 m', '134 m', '150 m', 'B', 'La flèche de la cathédrale d''Amiens culmine à 112 m. La cathédrale elle-même mesure 145 m de long et 42,3 m de haut sous voûte. Un chef-d''œuvre gothique !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Quel clown célèbre est devenu une figure du Carnaval de Dunkerque ?', 'Bozo', 'Cô Pinard', 'Pierrot', 'Arlequin', 'B', 'Cô Pinard est un personnage emblématique du Carnaval de Dunkerque. Son nom est un jeu de mots entre « copain » et « pinard » (vin). Il incarne l''esprit festif !'),
('Braderie de Lille', 'texte', NULL, 'Combien de jours dure la Braderie de Lille ?', '1 jour', '2 jours', '3 jours', '1 semaine', 'B', 'La Braderie se déroule sur 2 jours : le samedi et le dimanche du premier week-end de septembre. Les stands ouvrent le samedi à 14h et ferment le dimanche à 23h !'),
('Histoire & Mines', 'texte', NULL, 'En quelle année la dernière mine de charbon du Nord-Pas-de-Calais a-t-elle fermé ?', '1970', '1980', '1990', '2000', 'C', 'La fosse 9 de l''Escarpelle à Oignies a fermé le 21 décembre 1990, marquant la fin de 270 ans d''exploitation du charbon dans le Nord !'),
('Paris-Roubaix & Sport', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/ena_16_9_extra_big/2021/10/03/node_1079070/53619251/public/2021/10/03/B9728528015Z.1_20211003201526_000%2BGAMJ2EPUQ.4-0.jpg?itok=J-eEpxob1633284936', 'Quel surnom les coureurs donnent-ils à Paris-Roubaix quand il pleut ?', 'La Boueuse', 'L''Enfer boueux', 'Paris-Roubaix mouillé', 'La course de la gadoue', 'A', 'Quand il pleut sur Paris-Roubaix, la course devient apocalyptique : boue, chutes, crevaisons. Les éditions pluvieuses sont les plus légendaires !'),
('Célébrités du Nord', 'image', 'https://histoire-image.org/sites/default/files/2021-11/mai12_baschet_001f.jpg', 'Quel maréchal de France né à Tarbes mais enterré aux Invalides a commandé les forces alliées en 1918 ?', 'Pétain', 'Foch', 'Joffre', 'Lyautey', 'B', 'Ferdinand Foch a été le commandant suprême des forces alliées en 1918. Bien que né à Tarbes, il est étroitement lié à la victoire sur le front du Nord !'),
('Cinéma & Culture', 'image', 'https://woody.cloudly.space/app/uploads/lille-tourisme/2023/11/thumbs/LaM-Laurent-Javoy-10-1-min-1920x960-crop-1699001402.jpg', 'Quel musée d''art moderne se situe à Villeneuve-d''Ascq ?', 'Le Palais des Beaux-Arts', 'Le LaM (Lille Métropole Musée)', 'Le Centre Pompidou Nord', 'Le MAMCS', 'B', 'Le LaM de Villeneuve-d''Ascq est l''un des rares musées au monde à réunir art moderne, art contemporain et art brut dans un même lieu, au milieu d''un parc de sculptures !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce que le « Père Fouettard » dans la tradition du Nord ?', 'Le père Noël du Nord', 'Le compagnon de Saint-Nicolas qui punit les enfants pas sages', 'Un géant de carnaval', 'Un personnage de conte flamand', 'B', 'Le Père Fouettard accompagne Saint-Nicolas le 6 décembre. Vêtu de noir, il menace les enfants désobéissants de coups de fouet ou de charbon !'),
('Gastronomie', 'texte', NULL, 'Quelle bière blonde du Nord est brassée à Jenlain et porte le nom de son village ?', 'La Goudale', 'La Jenlain', 'La 3 Monts', 'La Choulette', 'B', 'La bière de Jenlain, brassée par la brasserie Duyck depuis 1922, est l''une des premières bières artisanales françaises à avoir connu un succès national !'),
('Patois', 'texte', NULL, 'Que signifie « un brav''humme » en ch''ti ?', 'Un homme courageux', 'Un homme gentil et honnête', 'Un homme fort', 'Un homme âgé', 'B', '« Un brav''humme » désigne un homme gentil, honnête et généreux en ch''ti. C''est un compliment très fort dans le Nord, synonyme de fiabilité et de bonté !'),
('Géographie', 'texte', NULL, 'Quelle ville du Nord est célèbre pour sa dentelle et son carnaval ?', 'Lille', 'Bailleul', 'Calais', 'Bergues', 'B', 'Bailleul est connue pour son musée de la dentelle et son carnaval historique. La ville a été presque entièrement reconstruite après la Première Guerre mondiale.'),
('Carnaval de Dunkerque', 'audio', 'chanson_les_3_cafes.mp3', 'Quelle chanson populaire est chantée par toute la foule en fin de bande ?', 'La Marseillaise', 'L''Ami Bidasse', 'La Cantate à Jean Bart', 'Les Corons', 'C', 'La Cantate à Jean Bart est le moment le plus émouvant de chaque bande. Des milliers de voix entonnent ensemble cet hommage au corsaire dunkerquois !'),
('Braderie de Lille', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/vdn_scale_664w/2024/09/14/node_1501909/60680719/public/2024/09/14/25690241.jpeg?itok=omGahhFY1726316329', 'Quel type de stand est le plus recherché par les collectionneurs à la Braderie ?', 'Les stands de vêtements', 'Les stands d''antiquités et brocante', 'Les stands de nourriture', 'Les stands de jouets', 'B', 'Les stands d''antiquités et brocante du Vieux-Lille sont les plus prisés. On y trouve des meubles anciens, de la vaisselle vintage et des objets rares !'),
('Histoire & Mines', 'image', 'https://image.jimcdn.com/app/cms/image/transf/dimension=origxorig:format=jpg/path/sd6574a70c7e756ed/image/ia63e7e9d8be1c905/version/1440623426/image.jpg', 'Comment s''appelle la grande fosse minière d''Arenberg transformée en lieu culturel ?', 'Le Métaphone', 'La Fosse d''Arenberg / Le 9-9bis', 'Le Centre Minier de Lens', 'La Cité des Mineurs', 'B', 'Le 9-9bis d''Oignies est un ancien site minier reconverti en pôle culturel. Il abrite le Métaphone, une salle de concert dont la façade réagit au son !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Combien de secteurs pavés compte environ le parcours de Paris-Roubaix ?', '15', '20', '30', '40', 'C', 'Le parcours de Paris-Roubaix comporte environ 30 secteurs pavés sur 55 km au total. Ils sont classés de 1 à 5 étoiles selon leur difficulté !'),
('Célébrités du Nord', 'texte', NULL, 'Quel humoriste né à Armentières est connu pour ses one-man-shows en ch''ti ?', 'Franck Dubosc', 'Dany Boon', 'Elie Semoun', 'Gad Elmaleh', 'B', 'Avant le cinéma, Dany Boon était un humoriste de stand-up célèbre pour ses sketches en ch''ti. Son spectacle « Waïka » a été vu par des millions de personnes !'),
('Cinéma & Culture', 'texte', NULL, 'Quelle série télévisée française se déroule dans un commissariat de Dunkerque ?', 'Capitaine Marleau', 'Engrenages', 'Profilage', 'Malaterra', 'D', 'Malaterra (2014) se déroule sur la Côte d''Opale et a été tournée à Boulogne-sur-Mer et alentours. L''ambiance brumeuse du littoral nordiste est un personnage à part entière !'),
('Traditions & Folklore', 'texte', NULL, 'Comment s''appelle la course d''ânes traditionnelle dans certains villages du Nord ?', 'Le concours hippique', 'La course aux ânes (ou ânade)', 'La course des baudets', 'Le galop flamand', 'B', 'L''ânade est une course d''ânes folklorique dans les villages du Nord. Les participants montent à cru et l''âne s''arrête souvent en chemin, au grand amusement du public !');
INSERT INTO questions (theme, type_media, url_media, question, reponse_A, reponse_B, reponse_C, reponse_D, bonne_reponse, anecdote) VALUES
('Gastronomie', 'texte', NULL, 'Qu''est-ce que la « tartine de Maroilles » servie dans les estaminets ?', 'Du pain grillé avec du Maroilles fondu', 'Une tartine froide avec du jambon', 'Un gâteau au fromage', 'Une crêpe au Maroilles', 'A', 'La tartine de Maroilles, c''est du pain de campagne généreusement recouvert de Maroilles et passé au four. L''odeur est puissante mais le goût est divin !'),
('Patois', 'texte', NULL, 'Que signifie « déquer » en ch''ti ?', 'Décorer', 'Descendre', 'Démolir', 'Découper', 'B', '« Déquer » signifie « descendre » en ch''ti. On dit « j''déque les escaliers » pour « je descends les escaliers ». C''est le contraire de « monquer » (monter) !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Quel est le nom du tambour-major qui mène la bande de Carnaval ?', 'Le chef de bande', 'Le tambour-major', 'Le meneur', 'Le capitaine', 'B', 'Le tambour-major est la figure centrale de chaque bande. Il mène le cortège avec sa grande canne et rythme la marche des fifres et tambours !'),
('Géographie', 'image', 'https://upload.wikimedia.org/wikipedia/commons/f/f7/Montreuil-sur-Mer_et_sa_citadelle.jpg', 'Quelle ville fortifiée de la Côte d''Opale a servi de QG aux Britanniques pendant la Première Guerre mondiale ?', 'Boulogne-sur-Mer', 'Montreuil-sur-Mer', 'Calais', 'Étaples', 'B', 'Montreuil-sur-Mer, malgré son nom, est à 15 km de la mer ! Ses remparts et sa citadelle en ont fait le quartier général du Field Marshal Haig en 14-18.'),
('Braderie de Lille', 'texte', NULL, 'Quelle est la tradition pour les restaurateurs lillois le lendemain de la Braderie ?', 'Fermer pendant une semaine', 'Mesurer la hauteur de leurs coquilles de moules', 'Faire un défilé de chars', 'Offrir des moules gratuites', 'B', 'Le lundi matin après la Braderie, les restaurateurs (et les médias) mesurent solennellement la hauteur des montagnes de coquilles. Un concours très sérieux !'),
('Histoire & Mines', 'texte', NULL, 'Quel acte héroïque des mineurs de Courrières en 1906 a stupéfié le monde ?', 'Ils ont éteint un incendie souterrain', 'Des rescapés sont remontés vivants 20 jours après l''explosion', 'Ils ont sauvé un village entier', 'Ils ont découvert une nappe d''eau souterraine', 'B', 'Le 30 mars 1906, 20 jours après la catastrophe, 13 mineurs sont remontés vivants, ayant survécu dans le noir total en mangeant de l''écorce de bois et buvant de l''eau suintante !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel est le premier coureur non-européen à avoir remporté Paris-Roubaix ?', 'Lance Armstrong', 'Greg LeMond', 'Stuart O''Grady', 'Cadel Evans', 'C', 'L''Australien Stuart O''Grady a remporté Paris-Roubaix en 2007, devenant le premier coureur d''Océanie à triompher sur les pavés du Nord !'),
('Célébrités du Nord', 'texte', NULL, 'Quel footballeur originaire du Nord a été élu meilleur joueur de la Coupe du Monde 2018 ?', 'Paul Pogba', 'Raphaël Varane', 'Antoine Griezmann', 'N''Golo Kanté', 'B', 'Raphaël Varane, né à Lille en 1993, a été un pilier de l''équipe de France championne du monde 2018. Formé au RC Lens, il a brillé au Real Madrid !'),
('Cinéma & Culture', 'audio', 'extrait_germinal_film.mp3', 'Quel acteur incarne Étienne Lantier dans le film « Germinal » de Claude Berri en 1993 ?', 'Gérard Depardieu', 'Renaud', 'Jean Reno', 'Daniel Auteuil', 'B', 'Le chanteur Renaud joue le rôle d''Étienne Lantier dans cette adaptation grandiose du roman de Zola, tournée en partie dans le Nord !'),
('Traditions & Folklore', 'image', 'https://www.plusaunord.com/wp-content/uploads/2019/12/Arras-marche-de-Noel-place-de-nuit.jpg', 'Quel marché de Noël des Hauts-de-France est réputé pour son village de chalets sur la Grand''Place ?', 'Le marché de Noël de Lille', 'Le marché de Noël d''Arras', 'Le marché de Noël d''Amiens', 'Le marché de Noël de Dunkerque', 'B', 'Le marché de Noël d''Arras, sur la Grand''Place et la Place des Héros, est l''un des plus beaux du nord de la France, avec 130 chalets et une grande roue !'),
('Gastronomie', 'image', 'https://hellonelo.com/wp-content/uploads/2021/11/hellonelo_speculoos_saint_nicolas_005-800x1000.jpg', 'Quel biscuit épicé, cousin du spéculoos belge, est une tradition dans le Nord ?', 'Le sablé', 'Le spéculoos', 'Le petit-beurre', 'Le macaron', 'B', 'Le spéculoos du Nord est un biscuit croquant épicé (cannelle, girofle, muscade) traditionnellement offert pour la Saint-Nicolas. Chaque boulangerie a sa recette secrète !'),
('Patois', 'audio', 'expression_hein_biloute.mp3', 'Que signifie « dins ch''temps-là » en ch''ti ?', 'À ce moment-là', 'Dans ces temps-là / autrefois', 'Tout de suite', 'Pas maintenant', 'B', '« Dins ch''temps-là » signifie « dans ces temps-là » ou « autrefois ». C''est une expression nostalgique très utilisée par les anciens du Nord !'),
('Géographie', 'texte', NULL, 'Quelle est la plus grande ville des Hauts-de-France ?', 'Amiens', 'Lille', 'Dunkerque', 'Calais', 'B', 'Lille Métropole Européenne regroupe plus d''un million d''habitants, faisant de Lille la plus grande ville de la région et la 4e métropole de France !'),
('Carnaval de Dunkerque', 'image', 'https://www.weo.fr/1729859751/rgnumlynqrbnkyicob1atkzvpkmd/optimized_picture-carnaval_de_dunkerque_2025.jpg', 'Combien de personnes participent en moyenne à la Bande de Dunkerque ?', '5 000', '15 000', '30 000 à 40 000', '100 000', 'C', 'La Bande de Dunkerque réunit 30 000 à 40 000 carnavaleux dans les rues ! C''est l''une des plus grandes fêtes populaires de France.'),
('Braderie de Lille', 'texte', NULL, 'Quel plat alternatif aux moules-frites gagne en popularité à la Braderie ?', 'Les crêpes', 'Le welsh', 'Les churros', 'Les burgers', 'B', 'Le welsh (fondu de cheddar à la bière sur pain grillé) devient de plus en plus populaire à la Braderie. Certains le préfèrent aux moules-frites !'),
('Histoire & Mines', 'image', 'https://bassinminier-patrimoinemondial.org/wp-content/uploads/2014/11/371.jpg', 'Comment appelle-t-on les ensembles de logements ouvriers avec jardins construits par les compagnies minières ?', 'Les immeubles sociaux', 'Les cités-jardins', 'Les HLM miniers', 'Les résidences ouvrières', 'B', 'Les cités-jardins sont un modèle d''habitat ouvrier avec maisons individuelles et jardins, inspiré du mouvement anglo-saxon. Elles donnent un charme unique au bassin minier !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quelle équipe cycliste pro était basée dans le Nord et portait les couleurs de la région ?', 'Quick-Step', 'Cofidis', 'AG2R', 'Groupama-FDJ', 'B', 'Cofidis, basée à Villeneuve-d''Ascq depuis 1997, est l''équipe cycliste du Nord par excellence. Elle participe au Tour de France et aux grandes classiques !'),
('Célébrités du Nord', 'image', 'https://thumb.canalplus.pro/http/unsafe/1440x810/filters:quality(80)/img-hapi.canalplus.pro:80/ServiceImage/ImageID/109529499', 'Quel acteur français, né à Lille, a joué dans « Le Vieux Fusil » et « Cinema Paradiso » ?', 'Jean-Paul Belmondo', 'Philippe Noiret', 'Michel Piccoli', 'Alain Delon', 'B', 'Philippe Noiret (1930-2006), né à Lille, est l''un des plus grands acteurs français. Il a tourné plus de 100 films et remporté deux César !'),
('Cinéma & Culture', 'texte', NULL, 'Quel festival de musique se tient à Aulnoye-Aymeries dans le Nord ?', 'Les Francofolies du Nord', 'Les Nuits Secrètes', 'Le Hellfest nordiste', 'Les Eurockéennes du Nord', 'B', 'Les Nuits Secrètes à Aulnoye-Aymeries proposent des concerts dans des lieux insolites et secrets : granges, usines, forêts... Un concept unique en France !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce qu''une « kermesse » dans le Nord ?', 'Un marché bio', 'Une fête de quartier ou d''école avec jeux et stands', 'Un concert en plein air', 'Un match de football', 'B', 'La kermesse est la fête populaire par excellence du Nord, organisée par les écoles et les paroisses avec jeux, tombola, pêche aux canards et barbe à papa !'),
('Gastronomie', 'texte', NULL, 'Quel est le lait utilisé pour fabriquer le fromage de Bergues ?', 'Du lait de chèvre', 'Du lait de vache écrémé', 'Du lait de brebis', 'Du lait entier de vache', 'B', 'Le fromage de Bergues est unique : il est fabriqué à partir de lait de vache écrémé et affiné en le lavant à la bière ! Il est plus léger que le Maroilles.'),
('Patois', 'texte', NULL, 'Comment dit-on « travailler » en ch''ti ?', 'Bosser', 'Ouvrer', 'Trimer', 'Boulotter', 'B', '« Ouvrer » est le verbe ch''ti pour « travailler ». On dit « j''ouvre à l''usine » pour « je travaille à l''usine ». Le mot vient du latin « operare ».'),
('Géographie', 'image', 'https://www.nemea-appart-hotel.com/media/cache/cms_lg/media/hortillonnages-d-amiens2-66fa662c32762227132141.jpg', 'Comment s''appellent les jardins flottants d''Amiens, cultivés depuis le Moyen Âge ?', 'Les marais d''Amiens', 'Les hortillonnages', 'Les polders picards', 'Les jardins d''eau', 'B', 'Les hortillonnages d''Amiens sont 300 hectares de jardins flottants sillonnés de canaux. On les visite en barque traditionnelle et on y cultive légumes et fleurs depuis le Moyen Âge !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Que jette-t-on en plus des harengs depuis le balcon de la mairie de Dunkerque ?', 'Des oranges', 'Des jouets et des friandises', 'Des pièces de monnaie', 'Des flocons de neige', 'B', 'En plus des harengs fumés, le maire jette des jouets, des bonbons et même des homards en plastique ! C''est la folie sur la place Jean Bart.'),
('Histoire & Mines', 'texte', NULL, 'Comment appelle-t-on la grève des mineurs de 1941 dans le Nord occupé par les Allemands ?', 'La Grande Grève', 'La Grève patriotique de mai-juin 1941', 'La Résistance minière', 'La Grève du charbon', 'B', 'En mai-juin 1941, 100 000 mineurs du Nord se mettent en grève contre l''occupant nazi. C''est le plus grand mouvement de résistance collective en France occupée !'),
('Célébrités du Nord', 'texte', NULL, 'Quel architecte lillois a conçu la tour de Lille, gratte-ciel emblématique du quartier Euralille ?', 'Jean Nouvel', 'Christian de Portzamparc', 'Rem Koolhaas', 'Renzo Piano', 'C', 'Rem Koolhaas, l''architecte néerlandais, a conçu le masterplan d''Euralille et la tour Lille Europe (rebaptisée tour de Lille), inaugurée en 1995. Un geste architectural audacieux !'),
('Cinéma & Culture', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/ena_16_9_extra_big/2018/04/26/node_366614/39429287/public/2018/04/26/B9715527719Z.1_20180426185631_000%2BG9FB690B9.4-0.jpg?itok=jp30vCSS1524808146', 'Quel ancien bâtiment postal de Lille est devenu un lieu d''expositions d''art contemporain ?', 'La Gare Saint-Sauveur', 'Le Tripostal', 'L''Hospice Comtesse', 'La Maison Folie', 'B', 'Le Tripostal, ancien centre de tri postal près de la gare Lille-Flandres, accueille les expositions de Lille3000 dans un espace brut de 6 000 m² !'),
('Traditions & Folklore', 'audio', 'musique_estaminet.mp3', 'Quel jeu de grenouilles est typique des estaminets du Nord ?', 'Le billard hollandais', 'La grenouille (ou jeu de tonneau)', 'Les dominos', 'Le jeu de l''oie', 'B', 'Le jeu de grenouille consiste à lancer des palets en fonte dans la gueule d''une grenouille en métal fixée sur un tonneau. C''est le roi des jeux d''estaminet !');
INSERT INTO questions (theme, type_media, url_media, question, reponse_A, reponse_B, reponse_C, reponse_D, bonne_reponse, anecdote) VALUES
('Gastronomie', 'texte', NULL, 'Qu''est-ce qu''un « cornet de frites » dans le Nord ?', 'Une crêpe roulée aux frites', 'Des frites servies dans un cône en papier', 'Un dessert en forme de cornet', 'Une frite géante', 'B', 'Le cornet de frites, c''est un cône de papier kraft rempli de frites fraîches. On le mange en marchant, dehors, quelle que soit la météo. C''est le street food du Nord !'),
('Patois', 'image', 'https://www.comptoirdesflandres.com/wp-content/uploads/2020/06/B9722384273Z.1_20200131170524_000GPGFE2OTK.1-0-jpg.webp', 'Que signifie « Min garchon » en ch''ti ?', 'Mon jardin', 'Mon garçon / Mon fils', 'Mon garage', 'Mon ami', 'B', '« Min garchon » signifie « mon garçon » ou « mon fils ». Le ch''ti transforme souvent le « ç » français en « ch » : garçon → garchon !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Quelle est la couleur dominante des costumes de la Bande de Malo ?', 'Le rouge', 'Le bleu et blanc', 'Le jaune', 'Le vert', 'B', 'La Bande de Malo-les-Bains a ses propres traditions et couleurs. Chaque bande a son identité propre, ce qui fait la richesse du Carnaval dunkerquois !'),
('Géographie', 'texte', NULL, 'Quel tunnel sous-marin relie Coquelles (Nord) à Folkestone (Angleterre) ?', 'Le Tunnel de la Manche', 'Le Tunnel du Détroit', 'Le Chunnel', 'L''Eurostar', 'A', 'Le Tunnel sous la Manche, long de 50 km (dont 38 sous la mer), a été inauguré en 1994. C''est le plus long tunnel sous-marin du monde !'),
('Braderie de Lille', 'image', 'https://lvdneng.rosselcdn.net/sites/default/files/dpistyles_v2/vdn_4_3_1279w/2022/09/04/node_1223987/55598048/public/2022/09/04/B9731984777Z.1_20220904000214_000%2BGSGL69N96.3-0.jpg?itok=loAfzHcG1662293183', 'À quelle heure la Braderie de Lille commence-t-elle traditionnellement le samedi ?', 'À 8h du matin', 'À 14h', 'À minuit', 'À 10h', 'B', 'La Braderie commence officiellement le samedi à 14h, mais les plus enthousiastes installent leurs stands dès la veille au soir !'),
('Histoire & Mines', 'texte', NULL, 'Quel métier consistait à abattre le charbon au pic dans la mine ?', 'Le galibot', 'Le haveur', 'Le porion', 'Le boiseur', 'B', 'Le haveur était le mineur qui abattait le charbon à la force de ses bras, au pic ou au marteau-piqueur. C''était le métier le plus dur et le plus dangereux de la mine.'),
('Paris-Roubaix & Sport', 'audio', 'ambiance_velodrome_roubaix.mp3', 'En quelle année a eu lieu la première édition de Paris-Roubaix ?', '1886', '1896', '1900', '1910', 'B', 'Paris-Roubaix a été créé en 1896 par Théodore Vienne, propriétaire du vélodrome de Roubaix. La course a été créée pour tester la nouvelle piste !'),
('Célébrités du Nord', 'texte', NULL, 'Quelle présentatrice TV née à Dunkerque a animé « C''est mon choix » ?', 'Laurence Ferrari', 'Évelyne Thomas', 'Karine Le Marchand', 'Sophie Davant', 'B', 'Évelyne Thomas, née à Dunkerque en 1964, a présenté « C''est mon choix » sur France 3 de 1999 à 2004. L''émission a été un phénomène télévisuel !'),
('Cinéma & Culture', 'texte', NULL, 'Quel événement culturel annuel illumine les rues d''Amiens en décembre ?', 'Les Lumières d''Amiens', 'Le Marché de Noël d''Amiens', 'Amiens, le spectacle de lumières sur la cathédrale', 'Le Festival des Lanternes', 'C', 'Chaque soir de décembre, la cathédrale d''Amiens est illuminée aux couleurs médiévales, restituant les polychromies d''origine de sa façade. Un spectacle magique !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce que le « billard Nicolas » joué dans les estaminets ?', 'Un billard classique', 'Un billard sans poches avec des quilles', 'Un jeu de cartes', 'Un jeu de plateau', 'B', 'Le billard Nicolas (ou billard à bouchons) est un jeu flamand où l''on fait tomber de petites quilles disposées sur la table à l''aide de billes. Passionnant !'),
('Gastronomie', 'image', 'https://recettes.precuttech.com/wp-content/uploads/2024/12/Waterzoi-de-poulet-cremeux.jpg', 'Quel plat flamand est un ragoût crémeux de poulet ou de poisson ?', 'Le hochepot', 'Le waterzoï', 'La choucroute', 'Le pot-au-feu', 'B', 'Le waterzoï (ou waterzooi) est un ragoût crémeux originaire de Gand mais très populaire dans le Nord. La version au poulet est la plus répandue !'),
('Patois', 'texte', NULL, 'Que signifie « tertous » en ch''ti ?', 'Toujours', 'Tous, tout le monde', 'Partout', 'Parfois', 'B', '« Tertous » signifie « tous » ou « tout le monde » en ch''ti. On dit « on y va tertous ! » pour « on y va tous ensemble » !'),
('Géographie', 'image', 'https://upload.wikimedia.org/wikipedia/commons/5/55/Place_des_H%C3%A9ros_d%27Arras_by_day_2012.jpg', 'Quelle ville du Nord est célèbre pour ses deux places bordées de maisons à arcades de style baroque flamand ?', 'Lille', 'Arras', 'Douai', 'Cambrai', 'B', 'Arras possède la Grand''Place et la Place des Héros, bordées de 155 maisons à arcades baroques flamandes. Un ensemble architectural unique en France !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Quel est le surnom affectueux donné aux participants du Carnaval de Dunkerque ?', 'Les fêtards', 'Les carnavaleux', 'Les zotches', 'Les joyeux', 'B', 'Les « carnavaleux » sont les participants au Carnaval de Dunkerque. Être carnavaleux, c''est un mode de vie, pas juste un déguisement !'),
('Braderie de Lille', 'texte', NULL, 'Comment appelle-t-on le nettoyage monumental de Lille après la Braderie ?', 'Le grand ménage', 'La grande lessive', 'Le balayage de la Braderie', 'La remise en état', 'A', 'Plus de 500 agents de nettoyage interviennent dès le dimanche soir pour nettoyer Lille. Ils ramassent environ 500 tonnes de déchets en quelques heures !'),
('Histoire & Mines', 'image', 'https://www.imt-formation-continue.fr/doc_client/campus%20Bourseul%202.jpg', 'Quel était l''unique moyen de descendre au fond de la mine ?', 'Des échelles', 'La cage (ascenseur de mine)', 'Un toboggan', 'Des escaliers en colimaçon', 'B', 'La cage est l''ascenseur qui descendait les mineurs et remontait le charbon. Elle pouvait transporter 50 hommes sur plus de 500 m de profondeur en quelques secondes !'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel coureur français, surnommé « le Blaireau », a échoué 4 fois à Paris-Roubaix sans jamais gagner ?', 'Raymond Poulidor', 'Bernard Hinault', 'Laurent Jalabert', 'Jacques Anquetil', 'B', 'Bernard Hinault, quintuple vainqueur du Tour de France, n''a jamais pu dompter les pavés de Paris-Roubaix malgré 4 tentatives. La course lui résistait !'),
('Célébrités du Nord', 'image', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSOwoZwisx7tQ84e4LKdeUkJGYSuTVS0Hf83w&s', 'Quel inventeur né à Fabrezan mais lié au Nord a conçu théoriquement le phonographe avant Edison ?', 'Louis Pasteur', 'Charles Cros', 'Gustave Eiffel', 'Auguste Lumière', 'B', 'Charles Cros a déposé un mémoire sur le « paléophone » en avril 1877, avant le phonographe d''Edison (décembre 1877) ! Mais il n''a jamais pu construire son prototype.'),
('Cinéma & Culture', 'image', 'https://media.abcsalles.com/images/1/salles/900h/11320/la-gare-saint-sauveur-1.jpg', 'Quel ancien triage ferroviaire lillois est devenu un pôle culturel et festif ?', 'Le Tripostal', 'La Gare Saint-Sauveur', 'La Halle aux Sucres', 'La Friche Josaphat', 'B', 'La Gare Saint-Sauveur, ancienne gare de marchandises, est devenue un lieu de vie avec bars, restaurants, expos et concerts en plein air l''été. Un repaire lillois !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce qu''un « bourloire » dans le Nord ?', 'Un atelier de poterie', 'Une salle de jeu de boule flamande', 'Une salle de bal', 'Un fournil de boulangerie', 'B', 'Le bourloire est la salle dédiée au jeu de bourle (boule flamande). Ces salles, souvent au sous-sol des cafés, sont un patrimoine vivant des Flandres !'),
('Gastronomie', 'texte', NULL, 'Quel condiment piquant est incontournable dans un cornet de frites du Nord ?', 'La sauce algérienne', 'La sauce « samouraï »', 'Le tabasco', 'Le piment d''Espelette', 'B', 'La sauce samouraï, à base de mayonnaise pimentée, est devenue un classique des baraques à frites du Nord depuis les années 2000 !'),
('Patois', 'audio', 'expression_alors_hein.mp3', 'Que veut dire « Pèle dins sin nez ! » en ch''ti ?', 'Regarde ailleurs', 'Mêle-toi de tes affaires !', 'Mouche-toi !', 'Fais attention !', 'B', '« Pèle dins sin nez ! » (littéralement « pèle dans son nez ») signifie « mêle-toi de tes affaires ! ». Une expression imagée et très ch''ti !'),
('Géographie', 'texte', NULL, 'Quelle ville du Pas-de-Calais est connue pour son port de pêche, le premier de France ?', 'Calais', 'Boulogne-sur-Mer', 'Dunkerque', 'Étaples', 'B', 'Boulogne-sur-Mer est le premier port de pêche de France et le premier centre européen de traitement des produits de la mer !'),
('Carnaval de Dunkerque', 'image', 'https://phrnleng.rosselcdn.net/sites/default/files/dpistyles_v2/ena_16_9_extra_big/2023/12/14/node_194223/3391078/public/2023/12/14/B9735638213Z.1_20231214102328_000%2BGUCNUVMAT.1-0.jpg?itok=WkN6JqQd1702984819', 'Quel objet doré est le trophée le plus convoité lors du jet de harengs ?', 'Un hareng en plastique', 'Le hareng doré', 'La couronne du carnaval', 'La clé de la ville', 'B', 'Attraper le hareng doré (peint en or) lancé par le maire est le graal du carnavaleux dunkerquois. C''est un porte-bonheur très recherché !'),
('Histoire & Mines', 'texte', NULL, 'Quel compositeur a écrit « Les Corons » interprétée par Pierre Bachelet ?', 'Pierre Bachelet lui-même', 'Jean-Pierre Lang', 'Serge Gainsbourg', 'Michel Berger', 'B', 'C''est Jean-Pierre Lang qui a écrit les paroles des « Corons » et Pierre Bachelet la musique. La chanson, sortie en 1982, est devenue l''hymne du bassin minier !'),
('Célébrités du Nord', 'texte', NULL, 'Quel célèbre mime français est né à Strasbourg mais a vécu à Amiens ?', 'Charlie Chaplin', 'Marcel Marceau', 'Jacques Tati', 'Buster Keaton', 'B', 'Marcel Marceau a fait ses premières armes à Amiens avant de devenir le plus grand mime du monde. Son personnage « Bip » est universellement connu !'),
('Cinéma & Culture', 'texte', NULL, 'Quel roman de Jules Verne, natif d''Amiens, est le plus vendu au monde ?', 'Vingt mille lieues sous les mers', 'Le Tour du monde en quatre-vingts jours', 'De la Terre à la Lune', 'Michel Strogoff', 'B', 'Jules Verne a vécu à Amiens de 1871 à sa mort en 1905. « Le Tour du monde en 80 jours » reste son œuvre la plus populaire dans le monde !'),
('Traditions & Folklore', 'image', 'https://colombophilienpdc.com/wp-content/uploads/2020/11/lacher-pigeons.jpg', 'Quelle passion traditionnelle nordiste consiste à élever et faire concourir des pigeons ?', 'L''ornithologie sportive', 'La colombophilie', 'L''aviculture', 'Le tir aux pigeons', 'B', 'La colombophilie (élevage de pigeons voyageurs de compétition) est une passion ancestrale du Nord. Les « coulonneux » entraînent leurs pigeons pour des courses de centaines de km !'),
('Gastronomie', 'image', 'https://delsinnearchitecte.fr/wp-content/uploads/2019/02/Com_VincentDelsinne_BrasserieSaintSylvestreCappel_C-JulienLanoo_20161223-5754-copy-bis.jpg', 'Quelle bière blonde de garde du Nord est brassée à Saint-Sylvestre-Cappel ?', 'La Jenlain', 'La 3 Monts', 'La Goudale', 'L''Anosteké', 'B', 'La 3 Monts, brassée par la brasserie de Saint-Sylvestre depuis 1985, tire son nom des trois monts des Flandres visibles depuis la brasserie !'),
('Patois', 'texte', NULL, 'Comment dit-on « un enfant » en ch''ti ?', 'Un gamin', 'Un tiot', 'Un drôle', 'Un minot', 'B', '« Un tiot » (prononcé « tcho ») signifie « un enfant » en ch''ti. On dit aussi « un tiot garchon » (un petit garçon) ou « eine tiote fille » (une petite fille) !'),
('Géographie', 'image', 'https://d3e1m60ptf1oym.cloudfront.net/53807244-0b18-11e2-aeeb-00259030440e/panorama_a%C3%A9rien_canche_uxga.jpg', 'Quelle station balnéaire du Nord est surnommée « le Jardin de la Manche » ?', 'Wimereux', 'Le Touquet-Paris-Plage', 'Berck-sur-Mer', 'Hardelot', 'B', 'Le Touquet-Paris-Plage, créé en 1882, est la station balnéaire la plus chic du Nord. Ses villas Belle Époque et sa forêt de pins lui valent son surnom !');
INSERT INTO questions (theme, type_media, url_media, question, reponse_A, reponse_B, reponse_C, reponse_D, bonne_reponse, anecdote) VALUES
('Gastronomie', 'texte', NULL, 'Qu''est-ce que la « Goudale » dans le Nord ?', 'Un plat régional', 'Une bière blonde de garde', 'Un fromage affiné', 'Un gâteau au genièvre', 'B', 'La Goudale est une bière blonde de garde brassée à Arques, dans le Pas-de-Calais. Son nom vient du picard « godale » (bonne ale). Elle est forte (7,2°) et dorée !'),
('Patois', 'texte', NULL, 'Que signifie « éne querelle » en ch''ti ?', 'Une chanson', 'Une dispute', 'Une question', 'Une quête', 'B', '« Éne querelle » signifie « une dispute » en ch''ti. Le Nord a la réputation d''aimer le débat animé, surtout autour d''une bière à l''estaminet !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Comment appelle-t-on les petits groupes de carnavaleux qui chantent ensemble dans les chapelles ?', 'Les chœurs', 'Les cliques', 'Les bandes secrètes', 'Les pelotons', 'B', 'Les « cliques » sont des groupes d''amis carnavaleux qui se retrouvent dans les chapelles pour chanter les chansons du répertoire carnavalesque avant la bande !'),
('Géographie', 'texte', NULL, 'Quel est le département le plus peuplé des Hauts-de-France ?', 'Le Pas-de-Calais', 'Le Nord', 'La Somme', 'L''Aisne', 'B', 'Le département du Nord compte environ 2,6 millions d''habitants, ce qui en fait le département le plus peuplé de France après Paris !'),
('Braderie de Lille', 'image', 'https://fabien-torre.fr/divers/albums/photos/8690698527487470-big.jpg', 'Quelle est la spécificité de la rue de Béthune pendant la Braderie ?', 'Elle est piétonne toute l''année', 'Elle accueille les plus grands stands professionnels', 'Elle est fermée pendant la Braderie', 'Elle est réservée aux artistes', 'B', 'La rue de Béthune, grande artère commerçante de Lille, accueille les stands professionnels les plus importants et les enseignes nationales pendant la Braderie !'),
('Histoire & Mines', 'image', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRutzUSHvqBj5OncKnXNtEgrqoCSXh8W-H_pw&s', 'Quel mémorial canadien surplombe les collines de Vimy dans le Pas-de-Calais ?', 'Le Mémorial de Thiepval', 'Le Mémorial national du Canada à Vimy', 'Le Monument aux morts de Lens', 'La Nécropole de Notre-Dame de Lorette', 'B', 'Le Mémorial de Vimy, inauguré en 1936, honore les 66 000 Canadiens morts pendant la Grande Guerre. La crête de Vimy a été prise par les Canadiens le 9 avril 1917.'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quelle est la distance totale de Paris-Roubaix ?', '180 km', '220 km', '257 km', '290 km', 'C', 'Paris-Roubaix fait environ 257 km, dont 55 km de pavés répartis en 30 secteurs. La course part en réalité de Compiègne (Oise), pas de Paris !'),
('Célébrités du Nord', 'texte', NULL, 'Quel rappeur originaire de Roubaix a cartonné avec « Brisé » et « Tout oublier » ?', 'Jul', 'Maître Gims', 'Soprano', 'Lartiste', 'D', 'Lartiste (Youssef Fathi Stitou), né à Strasbourg mais grandi à Roubaix, a mélangé rap et pop orientale. Ses tubes ont fait danser toute la France !'),
('Cinéma & Culture', 'image', 'https://somme.media.tourinsoft.eu/upload/PCUPIC0800010614-maisondejulesverne-amiens-somme-picardie2-ADRT80-AB.jpg', 'Quelle maison-musée d''Amiens est dédiée au célèbre écrivain de science-fiction ?', 'Le Musée de Picardie', 'La Maison de Jules Verne', 'Le Musée de la Tour Perret', 'La Villa Wells', 'B', 'La Maison de Jules Verne à Amiens, où l''écrivain vécut de 1882 à 1900, est un musée qui reconstitue son cabinet de travail et expose ses manuscrits !'),
('Traditions & Folklore', 'texte', NULL, 'Comment s''appelle le personnage malfaisant qui accompagne Saint-Nicolas dans le Nord ?', 'Le Krampus', 'Le Père Fouettard', 'Le Loup-garou', 'Le Bonhomme Hiver', 'B', 'Le Père Fouettard, vêtu de noir et portant un fouet, menace de mettre les enfants pas sages dans son sac. Heureusement, Saint-Nicolas est toujours là pour les protéger !'),
('Gastronomie', 'image', 'https://res.cloudinary.com/hv9ssmzrz/image/fetch/c_fill,f_auto,h_1125,q_auto:eco,w_1500/https://s3-eu-west-1.amazonaws.com/images-ca-1-0-1-eu/recipe_photos/original/245967/open-uri20250205-74-azwpu4', 'Qu''est-ce qu''une « ficelle picarde » ?', 'Un bonbon en forme de ficelle', 'Une crêpe roulée garnie de jambon, champignons et gruyère', 'Une baguette de pain fine', 'Un fil de saucisse piquante', 'B', 'La ficelle picarde, inventée en 1950 par Marcel Lefèvre à Amiens, est une crêpe roulée garnie de duxelles, jambon et crème, gratinée au four !'),
('Patois', 'audio', 'expression_allez_biloute.mp3', 'Que signifie l''expression « I fait un temps d''kien » en ch''ti ?', 'Il fait beau', 'Il fait un temps de chien (mauvais temps)', 'Il fait chaud', 'Il fait nuit', 'B', '« I fait un temps d''kien » signifie « il fait un temps de chien ». En ch''ti, « kien » remplace « chien ». C''est une expression très fréquente dans le Nord !'),
('Géographie', 'image', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRBXja1F9lY1OfIeu_hPoFQLNsJsUvpyHR_WQ&s', 'Quel château des Hauts-de-France abrite le musée Condé et ses trésors artistiques ?', 'Le château de Pierrefonds', 'Le château de Chantilly', 'Le château de Compiègne', 'Le château de Coucy', 'B', 'Le château de Chantilly abrite le musée Condé, la deuxième collection de peintures anciennes de France après le Louvre ! Et sa crème Chantilly est née ici.'),
('Carnaval de Dunkerque', 'audio', 'chanson_zinnekes_carnaval.mp3', 'Combien de chansons composent le répertoire traditionnel du Carnaval de Dunkerque ?', 'Une dizaine', 'Une vingtaine', 'Plus de 50', 'Plus de 100', 'C', 'Le répertoire carnavalesque dunkerquois compte plus de 50 chansons traditionnelles, des hymnes aux chansons grivoises. Les vrais carnavaleux les connaissent toutes par cœur !'),
('Histoire & Mines', 'texte', NULL, 'Comment s''appelle la plus grande nécropole militaire de France, dans le Pas-de-Calais ?', 'Verdun', 'Notre-Dame de Lorette', 'Le cimetière de Thiepval', 'Les Éparges', 'B', 'Notre-Dame de Lorette, à Ablain-Saint-Nazaire, est la plus grande nécropole militaire française (42 000 corps). L''anneau de la mémoire y porte 580 000 noms de soldats tombés.'),
('Célébrités du Nord', 'texte', NULL, 'Quel champion de boxe originaire de Denain a été champion du monde des mi-lourds ?', 'Marcel Cerdan', 'Jean-Marc Mormeck', 'Brahim Asloum', 'Fabrice Tiozzo', 'B', 'Jean-Marc Mormeck, né à Pointe-à-Pitre mais grandi à Denain, a été double champion du monde WBA-WBC des lourds-légers. Un héros du Nord !'),
('Cinéma & Culture', 'texte', NULL, 'Quel cirque permanent est installé dans un bâtiment Art déco à Amiens ?', 'Le cirque Pinder', 'Le Cirque Jules Verne', 'Le cirque d''Hiver', 'Le cirque Gruss', 'B', 'Le Cirque Jules Verne d''Amiens, construit en 1889, est l''un des seuls cirques permanents en dur de France. Il accueille spectacles et événements toute l''année !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce que le « chuque » dans les traditions du Nord ?', 'Un sport de combat', 'Un jet de sucreries lors des ducasses', 'Un cri de guerre', 'Un rituel viking', 'B', 'Le « chuque » ou « jets de bonbons » est la tradition de lancer des friandises depuis les chars de carnaval ou lors des ducasses. Les enfants adorent ça !'),
('Gastronomie', 'texte', NULL, 'Comment appelle-t-on la spécialité de Cambrai, bonbon au caramel et à la menthe ?', 'Les berlingots de Cambrai', 'Les bêtises de Cambrai', 'Les caramels de Cambrai', 'Les pastilles de Cambrai', 'B', 'Les bêtises de Cambrai ont été inventées par un apprenti confiseur qui a raté sa recette de caramels à la menthe. L''erreur a créé le bonbon le plus célèbre du Nord !'),
('Patois', 'texte', NULL, 'Que veut dire « ein canchon » en ch''ti ?', 'Un cochon', 'Une chanson', 'Un gros rhume', 'Un pardon', 'B', '« Ein canchon » signifie « une chanson » en ch''ti. Le ch''ti transforme souvent le « ch » français en « c » : chanson → canchon !'),
('Géographie', 'texte', NULL, 'Quel est le point culminant des Hauts-de-France ?', 'Le Mont Cassel (176 m)', 'Le Mont des Cats (164 m)', 'Le terril du 11/19 (186 m)', 'La colline de Laon (181 m)', 'C', 'Techniquement, les terrils du 11/19 à Loos-en-Gohelle (186 m) sont les plus hauts points des Hauts-de-France ! Un sommet artificiel créé par les mines.'),
('Braderie de Lille', 'texte', NULL, 'Quel est le surnom donné à la Braderie de Lille dans les médias ?', 'La foire aux bonnes affaires', 'Le plus grand vide-grenier d''Europe', 'La fête du Nord', 'Le marché géant', 'B', 'La Braderie est souvent surnommée « le plus grand vide-grenier d''Europe » par les médias, même si elle est bien plus que ça !'),
('Histoire & Mines', 'texte', NULL, 'Quel roi de France a conquis Lille en 1667 ?', 'Henri IV', 'Louis XIV', 'Louis XVI', 'François Ier', 'B', 'Louis XIV a conquis Lille lors de la Guerre de Dévolution en 1667. Il a ensuite fait construire la citadelle par Vauban pour protéger sa conquête !'),
('Paris-Roubaix & Sport', 'image', 'https://info.lenord.fr/upload/images/ca__paris_roubaix_trophee4_web-641990eca753a.jpg', 'De quelle couleur est le pavé-trophée du vainqueur de Paris-Roubaix ?', 'Gris naturel', 'Doré', 'Argenté', 'Bronze', 'A', 'Le pavé-trophée est un authentique pavé du Nord, laissé dans sa couleur gris naturel et monté sur un socle en bois. Simple, brut et prestigieux !'),
('Célébrités du Nord', 'image', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/8a/Alexandre-Marie_Desrousseaux.jpg/250px-Alexandre-Marie_Desrousseaux.jpg', 'Quel chansonnier lillois du XIXe siècle a composé « Le P''tit Quinquin » ?', 'Gustave Nadaud', 'Alexandre Desrousseaux', 'Pierre Dupont', 'Aristide Bruant', 'B', 'Alexandre Desrousseaux (1820-1892), chansonnier du peuple lillois, a écrit le P''tit Quinquin en 1853. Sa statue trône devant la mairie de Lille !'),
('Cinéma & Culture', 'texte', NULL, 'Quel événement festif gratuit transforme Lille en piste de danse géante chaque premier samedi de septembre ?', 'Le Bal de la Braderie', 'Le Bal de l''Europe', 'Le Grand Bal des Pompiers', 'La Fête de la Musique du Nord', 'A', 'Le Bal de la Braderie, le samedi soir, transforme la Grand''Place en gigantesque piste de danse. Des dizaines de milliers de personnes dansent jusqu''à l''aube !'),
('Traditions & Folklore', 'image', 'https://i0.wp.com/nord-escapade.com/wp-content/uploads/2017/09/Cabotan-somme-tourisme_GF.jpg?fit=800%2C520&ssl=1', 'Comment s''appelle le théâtre de marionnettes traditionnelles d''Amiens ?', 'Le Guignol du Nord', 'Le théâtre de Chés Cabotans d''Amiens', 'Le Petit Théâtre Picard', 'Les Marionnettes d''Amiens', 'B', 'Chés Cabotans d''Amiens est le théâtre de marionnettes à fils picardes. Le héros « Lafleur » est un soldat mutin, espiègle et bravache, né en 1811 !');
INSERT INTO questions (theme, type_media, url_media, question, reponse_A, reponse_B, reponse_C, reponse_D, bonne_reponse, anecdote) VALUES
('Gastronomie', 'image', 'https://node01.flagstat.net/media/image/1560r.jpg', 'Qu''est-ce que le « Hochepot » flamand ?', 'Un cocktail de bières', 'Un pot-au-feu flamand aux légumes et viandes variées', 'Un dessert au chocolat', 'Un pain aux lardons', 'B', 'Le Hochepot est un pot-au-feu flamand copieux avec oreilles et queue de porc, poitrine de bœuf, épaule de mouton et légumes d''hiver. Un plat de partage !'),
('Patois', 'texte', NULL, 'Que signifie « dénicher » en picard ?', 'Trouver quelque chose de rare', 'Voler des œufs d''oiseaux', 'Démanger', 'Descendre d''un arbre', 'A', 'En picard, « dénicher » a le même sens qu''en français standard : trouver quelque chose de caché ou de rare. Le picard a beaucoup influencé le français !'),
('Carnaval de Dunkerque', 'image', 'https://france3-regions.franceinfo.fr/image/zVy7eazJzE3UgBL1jd4LJ9-e1D0/1200x1200/regions/2020/06/09/5edee4b6754d9_jean_bart.jpg', 'La statue de Jean Bart sur la place de Dunkerque pointe son épée vers quelle direction ?', 'Vers l''Angleterre', 'Vers la mer du Nord', 'Vers la mairie', 'Vers le sud', 'B', 'La statue de Jean Bart, érigée en 1845, pointe son épée vers la mer du Nord, rappelant ses exploits maritimes contre les flottes ennemies !'),
('Géographie', 'texte', NULL, 'Combien de départements composent la région Hauts-de-France ?', '3', '4', '5', '6', 'C', 'Les Hauts-de-France comptent 5 départements : Nord, Pas-de-Calais, Somme, Aisne et Oise. La région a été créée en 2016 par fusion du Nord-Pas-de-Calais et de la Picardie.'),
('Braderie de Lille', 'texte', NULL, 'En moyenne, combien de bénévoles et agents assurent la sécurité de la Braderie ?', '500', '1 000', '3 000', '5 000', 'C', 'Environ 3 000 personnes (police, pompiers, bénévoles, agents de propreté) sont mobilisées pendant la Braderie pour assurer sécurité et logistique !'),
('Histoire & Mines', 'image', 'https://i0.wp.com/nord-escapade.com/wp-content/uploads/2017/03/Lanneau-de-la-m%C3%A9moire-Ablain-Saint-Nazaire-Le-Pays-Lensois.jpg?fit=960%2C640&ssl=1', 'Comment s''appelle le mémorial en forme d''ellipse à Notre-Dame de Lorette qui porte 580 000 noms ?', 'Le Mur des noms', 'L''Anneau de la Mémoire', 'Le Cercle du souvenir', 'L''Arc de la Paix', 'B', 'L''Anneau de la Mémoire, inauguré en 2014, est une ellipse de 345 m de long portant les noms de 580 000 soldats de toutes nationalités tombés dans le Nord 14-18.'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel est le surnom du secteur pavé « Mons-en-Pévèle » sur Paris-Roubaix ?', 'Le Bourbier', 'Le Bout du monde', 'La Carrière', 'Le Chemin de croix', 'A', 'Le secteur de Mons-en-Pévèle est surnommé « Le Bourbier » car il se transforme en véritable marécage les jours de pluie. C''est un secteur 5 étoiles !'),
('Célébrités du Nord', 'texte', NULL, 'Quel homme politique né à Jeumont est devenu Premier ministre de la France en 2012 ?', 'François Fillon', 'Jean-Marc Ayrault', 'Manuel Valls', 'Lionel Jospin', 'B', 'Jean-Marc Ayrault, bien que député de Nantes, est originaire du Nord. Le Nord a donné à la France de nombreux hommes et femmes politiques !'),
('Cinéma & Culture', 'audio', 'extrait_chanson_corons.mp3', 'Dans la chanson « Les Corons », que raconte Pierre Bachelet ?', 'La vie d''un mineur à la retraite', 'La nostalgie d''une enfance dans les corons', 'Une histoire d''amour à Lens', 'Le carnaval de Dunkerque', 'B', '« Les Corons » évoquent avec nostalgie l''enfance dans les cités minières : les maisons identiques, les terrils, et la solidarité ouvrière. Un texte bouleversant !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce qu''un « échevin » dans les fêtes traditionnelles du Nord ?', 'Un danseur', 'Un adjoint au maire ou notable qui préside les cérémonies', 'Un musicien', 'Un cuisinier de fête', 'B', 'L''échevin est un titre médiéval encore utilisé dans les traditions flamandes du Nord. Il désigne un notable ou conseiller municipal qui préside les cérémonies festives.'),
('Gastronomie', 'texte', NULL, 'Quelle confiserie de Berck-sur-Mer est typique de la Côte d''Opale ?', 'Les sucettes au sirop', 'Les berlingots de Berck', 'Les nougats de Berck', 'Les caramels au beurre salé', 'B', 'Les berlingots de Berck sont les bonbons emblématiques de la station. Ils sont fabriqués artisanalement et vendus dans des sachets colorés sur la plage !'),
('Patois', 'audio', 'expression_vla_ti_pas.mp3', 'Que signifie « Vlo-ti pas ? » en ch''ti ?', 'Tu ne veux pas ?', 'Ne voilà-t-il pas ? (Tiens donc !)', 'Tu voles quoi ?', 'Tu vois pas ?', 'B', '« Vlo-ti pas ? » est une exclamation ch''ti qui signifie « Tiens donc ! » ou « Ne voilà-t-il pas ! ». On l''utilise pour exprimer la surprise ou l''indignation.'),
('Géographie', 'image', 'https://www.connaissancedesenergies.org/sites/connaissancedesenergies.org/files/infographie/Centrale%20nucl%C3%A9aire%20de%20Gravelines.jpg', 'Quelle ville du Nord abrite la plus puissante centrale nucléaire d''Europe ?', 'Dunkerque', 'Gravelines', 'Calais', 'Boulogne', 'B', 'La Centrale nucléaire de Gravelines, avec ses 6 réacteurs, est la plus puissante d''Europe occidentale (5 400 MW). Elle fournit un dixième de l''électricité française !'),
('Carnaval de Dunkerque', 'texte', NULL, 'Comment appelle-t-on le fait de reconnaître un ami déguisé et grimé au Carnaval ?', 'Le démasquage', 'L''intrique', 'Le repérage', 'La chasse aux masques', 'B', '« Intriguer » ou « faire l''intrique » consiste à deviner qui se cache sous le clet''che. C''est un jeu dans le jeu, très prisé des carnavaleux !'),
('Braderie de Lille', 'texte', NULL, 'Quelle gare lilloise est la plus proche du centre de la Braderie ?', 'Gare Lille-Europe', 'Gare Lille-Flandres', 'Gare Lille-Sud', 'Gare Saint-Sauveur', 'B', 'La Gare Lille-Flandres, reconstitution de l''ancienne Gare du Nord de Paris, est en plein centre de Lille, à deux pas de la Grand''Place et du cœur de la Braderie !'),
('Histoire & Mines', 'texte', NULL, 'Quel matériau de construction provient des briqueteries traditionnelles du Nord ?', 'Le grès', 'La brique rouge', 'Le calcaire', 'Le granit', 'B', 'La brique rouge est le matériau emblématique du Nord. Les briqueteries utilisaient l''argile locale pour produire ces briques qui donnent aux villes du Nord leur couleur typique.'),
('Paris-Roubaix & Sport', 'texte', NULL, 'Quel est le dernier secteur pavé de Paris-Roubaix avant le vélodrome ?', 'Le Pont Gibus', 'L''Espace Charles Crupelandt', 'Le Carrefour de l''Arbre', 'La Trouée d''Arenberg', 'B', 'L''Espace Charles Crupelandt, en pleine ville de Roubaix, est le tout dernier secteur pavé. Après quoi, les coureurs filent vers le vélodrome !'),
('Célébrités du Nord', 'texte', NULL, 'Quelle championne olympique de judo est née à Valenciennes ?', 'Clarisse Agbégnénou', 'Lucie Décosse', 'Gévrise Émane', 'Audrey Tcheuméo', 'A', 'Clarisse Agbégnénou, née à Rennes mais formée dans le Nord, est quintuple championne du monde et médaillée d''or olympique en judo !'),
('Cinéma & Culture', 'texte', NULL, 'Quel lieu culturel de Dunkerque est installé dans un ancien entrepôt à tabac ?', 'Le Tripostal du Nord', 'Le FRAC Grand Large', 'Le Musée du Port', 'La Halle aux Sucres', 'B', 'Le FRAC Grand Large, installé dans un ancien hangar portuaire du Quai de la Citadelle, présente des collections d''art contemporain dans un bâtiment spectaculaire !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce que la « Ronde de nuit » à Lille ?', 'Un spectacle son et lumière', 'Une visite guidée nocturne du vieux Lille', 'Un festival de jazz', 'Une fête foraine', 'B', 'Les rondes de nuit sont des visites guidées théâtralisées du Vieux-Lille, racontant l''histoire de la ville à travers anecdotes et légendes. C''est magique !'),
('Gastronomie', 'texte', NULL, 'Qu''appelle-t-on un « mitraillette » dans certaines baraques à frites du Nord ?', 'Un long pain garni de frites et viande avec sauce', 'Un fusil ancien', 'Un grand cornet de frites', 'Une saucisse géante', 'A', 'La mitraillette (ou « missile ») est un sandwich géant : une demi-baguette remplie de frites, viande et sauce. C''est la version XXL de l''américain !'),
('Patois', 'texte', NULL, 'Comment dit-on « la pluie » en ch''ti ?', 'L''orage', 'El''drache', 'El''ieu', 'L''trempe', 'B', '« El''drache » signifie « la pluie » (forte) en ch''ti. Le mot est d''origine flamande et témoigne de l''influence germanique sur le ch''ti !'),
('Géographie', 'texte', NULL, 'Quelle forêt domaniale près de Compiègne est l''une des plus vastes de France ?', 'La forêt de Fontainebleau', 'La forêt de Compiègne', 'La forêt de Rambouillet', 'La forêt de Saint-Gobain', 'B', 'La forêt de Compiègne couvre 14 500 hectares. C''est dans un wagon situé dans cette forêt que l''Armistice du 11 novembre 1918 a été signé !'),
('Carnaval de Dunkerque', 'texte', NULL, 'En quelle année le Carnaval de Dunkerque a-t-il fêté ses origines historiques remontant à l''époque ?', 'XVe siècle', 'XVIIe siècle', 'XIXe siècle', 'XVIIIe siècle', 'B', 'Le Carnaval de Dunkerque trouve ses origines au XVIIe siècle, quand les armateurs offraient un festin aux pêcheurs avant leur départ en mer pour la pêche à la morue en Islande !'),
('Histoire & Mines', 'audio', 'chant_mineurs.mp3', 'Comment appelle-t-on la Sainte-Barbe dans le monde minier ?', 'Un jour de repos', 'La fête patronale des mineurs (4 décembre)', 'Un outil de mine', 'Une prière du matin', 'B', 'La Sainte-Barbe, le 4 décembre, est la fête patronale des mineurs. Sainte Barbe est la patronne des artificiers et de tous ceux qui travaillent sous terre !'),
('Célébrités du Nord', 'image', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/37/Paul_Verlaine.jpeg/960px-Paul_Verlaine.jpeg', 'Quel poète symboliste est né à Metz mais a vécu et enseigné à Rethel et dans le Nord ?', 'Arthur Rimbaud', 'Paul Verlaine', 'Stéphane Mallarmé', 'Charles Baudelaire', 'B', 'Paul Verlaine a enseigné dans le Nord et y a eu sa liaison tumultueuse avec Rimbaud. On peut visiter les lieux de leur histoire à travers le Nord et les Ardennes !'),
('Cinéma & Culture', 'image', 'https://www.compagniedudragon.com/web/image/3079-bfa814c6/Photo_Dragon-Spectacle-2.jpg', 'Quel dragon mécanique géant déambule dans les rues de Calais ?', 'Le Dragon de Calais', 'Smaug', 'Le Dragon de Flandres', 'L''Hydre des ports', 'A', 'Le Dragon de Calais, machine de 72 tonnes et 25 m de long, crache du feu et emporte des passagers ! Il est né de la Compagnie du Dragon, inspirée des Machines de l''île de Nantes.'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce que la « fête du hareng » à Étaples-sur-Mer ?', 'Un concours de pêche', 'Une fête célébrant la tradition de la pêche avec dégustation gratuite de harengs', 'Un festival de musique', 'Un marché aux poissons', 'B', 'La fête du hareng à Étaples célèbre la tradition de la pêche. Des milliers de harengs sont grillés et distribués gratuitement sur le port !'),
('Gastronomie', 'image', 'https://www.lechtimarche.fr/modules/smartblog/images/76-large_default.jpg', 'Qu''est-ce que la « vergeoise » utilisée en pâtisserie dans le Nord ?', 'Un type de miel', 'Un sucre brun de betterave', 'Une confiture de fruits', 'Un sirop de canne', 'B', 'La vergeoise (brune ou blonde) est un sucre de betterave typique du Nord, au goût caramélisé. On l''utilise dans la tarte au sucre, les spéculoos et plein de recettes nordistes !'),
('Patois', 'texte', NULL, 'Que signifie « cafouilleux » en ch''ti et en français du Nord ?', 'Quelqu''un qui boit beaucoup de café', 'Quelqu''un de désorganisé, qui s''emmêle', 'Quelqu''un de joyeux', 'Quelqu''un de pressé', 'B', '« Cafouilleux » signifie « désordonné, embrouillé ». Le mot a d''ailleurs été adopté par le français standard ! C''est un cadeau du Nord à la langue française.'),
('Géographie', 'image', 'https://www.hotelsdelille.com/uploads/images/cms/hotels-de-lille-fete-nationale-citadelle.jpg', 'Quel surnom Vauban a-t-il donné à la citadelle de Lille qu''il a construite ?', 'La Belle du Nord', 'La Reine des Citadelles', 'La Forteresse Imprenable', 'L''Étoile du Nord', 'B', 'Vauban lui-même a surnommé sa citadelle de Lille « la Reine des Citadelles ». Sa forme en étoile à cinq branches est un chef-d''œuvre d''architecture militaire !'),
('Carnaval de Dunkerque', 'image', 'https://woody.cloudly.space/app/uploads/dunkerque/2024/01/thumbs/Carnaval-bals_2024-1920x960.jpg', 'Quel bal clôture traditionnellement la saison du Carnaval de Dunkerque ?', 'Le Bal du Corsaire', 'Le Bal du Gouverneur', 'Le Bal de la Mer', 'Le Bal des Adieux', 'B', 'Le Bal du Gouverneur clôture traditionnellement la saison carnavalesque. C''est un moment élégant qui contraste avec la folie des bandes de rue !'),
('Braderie de Lille', 'image', 'https://upload.wikimedia.org/wikipedia/commons/e/e3/Lille_gd_place_colonne.jpg', 'Quelle colonne se dresse au centre de la Grand''Place de Lille ?', 'La colonne de la Liberté', 'La colonne de la Déesse', 'La colonne Napoléon', 'La colonne des Flandres', 'B', 'La colonne de la Déesse commémore la résistance de la ville lors du siège autrichien de 1792. La légende dit que la Déesse montre du doigt les assaillants !'),
('Histoire & Mines', 'texte', NULL, 'Quelle spécificité architecturale distingue les corons des cités-jardins dans le bassin minier ?', 'Les corons ont des toits en ardoise', 'Les corons sont alignés en rangées serrées, les cités-jardins ont des jardins individuels', 'Les corons sont en pierre, les cités-jardins en brique', 'Il n''y a aucune différence', 'B', 'Les corons (1850-1900) sont des rangées de maisons identiques serrées. Les cités-jardins (1920-1940) offrent plus d''espace avec jardins et rues arborées !'),
('Paris-Roubaix & Sport', 'image', 'https://cloudfront-eu-central-1.images.arcpublishing.com/leparisien/BIUBUOEAVZEM7EACJG5PELJOEI.jpg', 'Comment sont surnommés les coureurs qui terminent Paris-Roubaix couverts de boue ?', 'Les gladiateurs du Nord', 'Les forçats de la route', 'Les lions des Flandres', 'Les guerriers des pavés', 'A', 'Les « gladiateurs du Nord » est le surnom donné aux coureurs qui bravent les pavés de Paris-Roubaix. Couverts de boue et de sang, ils incarnent le dépassement de soi !'),
('Célébrités du Nord', 'texte', NULL, 'Quel créateur de mode né à Caudry (Nord) est connu mondialement pour ses robes en dentelle ?', 'Jean-Paul Gaultier', 'Sophie Hallette', 'Christian Lacroix', 'Coco Chanel', 'B', 'Sophie Hallette n''est pas une personne mais une maison de dentelle de Caudry, fondée en 1887, qui a fourni la dentelle de la robe de mariée de Kate Middleton !'),
('Cinéma & Culture', 'texte', NULL, 'Quel prix littéraire est décerné chaque année dans le Nord et récompense un roman populaire ?', 'Le Prix Goncourt du Nord', 'Le Prix Marguerite de Flandre', 'Le Prix des lecteurs du Nord', 'Le Prix de la Braderie', 'C', 'Le Prix des lecteurs du Nord-Pas-de-Calais récompense chaque année un roman choisi par des lecteurs de la région. C''est un prix qui valorise la lecture populaire !'),
('Traditions & Folklore', 'image', 'https://www.francetravail.fr/files/live/sites/PE/files/secteurs-metiers/Artisanat/Textile-mode-luxe-850x523.jpg', 'Pour quelle industrie textile Calais et Caudry sont-elles mondialement réputées ?', 'Le lin', 'La dentelle', 'La laine', 'La soie', 'B', 'Calais et Caudry sont les capitales mondiales de la dentelle mécanique. La Cité internationale de la Dentelle et de la Mode de Calais retrace cette histoire !'),
('Gastronomie', 'texte', NULL, 'Quel est le fromage le plus puant du Nord, affiné dans la bière et souvent surnommé « le Puant » ?', 'Le Maroilles', 'Le Vieux-Lille', 'Le Bergues', 'La Boulette d''Avesnes', 'B', 'Le Vieux-Lille (ou « Puant de Lille ») est un Maroilles affiné 3 mois supplémentaires dans la saumure et la bière. Son odeur est extrême mais son goût est une explosion !'),
('Patois', 'texte', NULL, 'Comment salue-t-on quelqu''un en ch''ti ?', 'Salut, cha va ?', 'Bonjour, biloute !', 'Wesh, gros !', 'Allez, l''ami !', 'A', '« Salut, cha va ? » est la salutation ch''ti par excellence. Simple, directe et chaleureuse, comme les gens du Nord eux-mêmes !'),
('Géographie', 'texte', NULL, 'Quelle est la ville la plus à l''est des Hauts-de-France ?', 'Maubeuge', 'Hirson', 'Avesnes-sur-Helpe', 'Givet', 'B', 'Hirson, dans le département de l''Aisne, est située à l''extrême est des Hauts-de-France, à la frontière belge, au milieu de la forêt de Thiérache.'),
('Histoire & Mines', 'texte', NULL, 'Comment le charbon du Nord était-il principalement utilisé au XIXe siècle ?', 'Pour le chauffage domestique uniquement', 'Pour alimenter les machines à vapeur de l''industrie textile et métallurgique', 'Pour fabriquer des médicaments', 'Pour construire des routes', 'B', 'Le charbon du Nord a alimenté la révolution industrielle : machines à vapeur, hauts fourneaux, chemins de fer. C''est le « pain de l''industrie » qui a fait la richesse du Nord !'),
('Cinéma & Culture', 'image', 'https://cdn.s-pass.org/SPASSDATA/media/cache/portail_vignette_xl/SPASSDATA/attachments/2014_07/04/5f7f34f93fb46-d20236.jpg', 'Quel musée de Calais est dédié à l''industrie de la dentelle et de la mode ?', 'Le Musée du Textile de Roubaix', 'La Cité internationale de la Dentelle et de la Mode', 'Le Musée de la Broderie', 'La Maison de la Mode', 'B', 'La Cité de la Dentelle et de la Mode de Calais, installée dans une ancienne usine, présente des métiers en fonctionnement et des pièces de haute couture en dentelle !'),
('Traditions & Folklore', 'texte', NULL, 'Qu''est-ce que la « Thiérache » dans les Hauts-de-France ?', 'Un fromage', 'Une région naturelle célèbre pour ses églises fortifiées', 'Une danse traditionnelle', 'Un type de bière', 'B', 'La Thiérache, à cheval entre l''Aisne et le Nord, est une région bocagère ponctuée de 63 églises fortifiées en brique datant des XVIe-XVIIe siècles. Un patrimoine unique !'),
('Patois', 'texte', NULL, 'Ké qu''y a à magner quand on t''sert eune "Fricadelle" à baraque ?', 'Personne sait s''qu''y a d''dins !', 'Du bœuf haché pur', 'Cho ch''est eune saussiche au curry', 'Des loques broyées', 'A', 'Heureuch''ment qu''on sait nin cha qu''y a d''dins biloute, sinon on in mingero pu !'),
('Patois', 'texte', NULL, 'Quand in t''dit qu''t''es un "Baraqui", cha veut dire quoy ch''t''affaire là ?', 'T''es l''pro du barbecue', 'T''es un kéké d''kermesse', 'T''es né dans une baraque à frites', 'T''es l''roi du tuning', 'B', 'Un baraqui, ch''est quelqu''un qui a nin peur d''s''afficher avec s''survêt'' et s''banane su l''torse !'),
('Patois', 'texte', NULL, 'Qu''est-ce qu''in fait quand in "Brait comm'' un veau" ?', 'In rigolet', 'In pleure fort', 'In mange comme un goinfre', 'In crie après sin garchon', 'B', 'Braire ch''est pleurer ! Comm'' on dit : Dins ch''Nord on brait incore pus fort !'),
('Patois', 'texte', NULL, 'Si in t''fil'' des "Cagoules", qu''est ch''qui t''attind à l''fête ?', 'T''vas avoir caud à l''tête', 'T''vas mingert des escargots', 'T''vas lancer des harengs', 'T''vas boir'' du genièvre', 'B', 'Les cagoules (ou caracoles), ch''est des p''tits escargots cuits dans l''bouillon !'),
('Patois', 'texte', NULL, 'Que t''dirabe un camarade s''il t''trouve un peu "Babache" s''u l''moment ?', 'T''es bien habillé l''copain !', 'T''es eune blette, un idiot quoy !', 'T''as faim ou quoy ?', 'T''es in r''tard boudiou !', 'B', 'Être un babache (ou un bachelier du dimanche), c''est n''nin être fute-fute, min chou !'),
('Patois', 'texte', NULL, 'Queuch qu''i dit l''fieu quand ch''est l''heure d''boire ch''café ac ti ?', 'Jute l''café ? On y fout l''goutte !', 'J''penche pour eun'' tiote tasse', 'Vers'' eune bolée', 'Un grand jus d''caussettes', 'A', 'Mett'' la goutte din l''café ch''est une bonne vieille tradition po s''réchauffer l''carcasse !'),
('Patois', 'texte', NULL, 'Quand qu''ch''est l''heure d''fair'' "Bérot", in s''prépare por quoy ?', 'Por boir eune bière', 'Por r''garder l''télé', 'Por dormir min tiot', 'Por mingert tout s''n assiette', 'C', 'On fait bérot ch''est fère dodo. Souvent in dit cha aux tiots infants avant d''dormir !'),
('Patois', 'texte', NULL, '"Té m''fais tourner in bourrique", qu''est çô veut dire ?', 'Tu m''fais rire aux larmes', 'Tu m''rends dingue avuc tes bêtises', 'Tu danses cor à r''ver à l''ducasse', 'Tu boies gramint tro d''picons', 'B', 'Fère tourner in bourrique, ch''est casser les abattis d''quelqu''un tellement tu l''énerves !'),
('Patois', 'texte', NULL, 'Qué qu''ch''est qu''eune "Bistouille" l''matin boudiou ?', 'Un mourceau d''maroilles trempé din ch''café', 'Un tiot verre de genièvre ou d''l''eau-de-vie dans ch''café', 'Eune chique à l''menthe', 'Un pain crotté au beurre', 'B', 'La bistouille rature le gésier ! C''était l''café amélioré des mineurs minte pour affronter l''fro !'),
('Patois', 'texte', NULL, 'Si in t''dit qu''t''es "Brave" din ch''Nord, kék''ça sent tout bas ?', 'Que t''es un héros', 'Que t''es eun tiot biau, mais nin bien malin', 'Que t''es fou et picolard', 'Que t''as core tes dints d''lait', 'B', 'Quind on dit "Oh l''pauv'', il est brave...", ch''est pu de l''compassion d''vant la naïveté qu''autr'' choz !');
INSERT INTO questions (theme, type_media, url_media, question, reponse_A, reponse_B, reponse_C, reponse_D, bonne_reponse, anecdote) VALUES
('Patois', 'texte', NULL, 'En ch''ti, que signifie l''expression « Avoir la drisse au cul » ?', 'Être poursuivi par la police', 'Avoir une maladie vénérienne', 'Avoir peur', 'Être pressé d''y aller', 'C', 'Bien que l''expression évoque aussi la colique ("la drisse"), au sens figuré, ça signifie avoir très peur !'),
('Patois', 'texte', NULL, 'Une « tiote guernouille », c''est...', 'Un jouet de bébé', 'Un animal', 'Un petit discours', 'Un vêtement', 'B', 'La "guernouille" est la petite grenouille en patois picard. On l''emploie parfois de manière affectueuse pour un enfant.'),
('Patois', 'texte', NULL, '« Elle a des grosses tototes ma tante Charlotte ! » Que désignent les tototes ?', 'Les joues', 'Les oreilles', 'Les seins', 'Les poches', 'C', 'Les "tototes" désignent affectueusement la poitrine généreuse. L''expression est restée dans beaucoup de familles !'),
('Patois', 'texte', NULL, '« Eume voisine alle est pire qu''eune agache ». Que signifie ce mot ?', 'Une vache', 'Une chienne', 'Une pie', 'Une poule', 'C', 'L''agache (ou agache-écrevisse) est une pie. Dire qu''une voisine est une agache, c''est dire qu''elle est très bavarde !'),
('Patois', 'texte', NULL, 'Que traduisez-vous par : « Cha buque a''ch''bintinse ! » ?', 'Ça tangue sur le bateau !', 'Ça frappe à la porte !', 'Ça boit dans ce café !', 'Ça pue dans ce coin !', 'B', '« Buquer » signifie frapper, cogner. Ex: "Ch''est mi qu''z''allez buquer si j''fais des carabistouilles !"'),
('Patois', 'texte', NULL, 'Que veut-on te dire avec : « Quoque ch''est qu''tu berdoulles ? »', 'Tu prépares', 'Tu bredouilles', 'Tu malaxes', 'Tu cuisines', 'B', 'Berdouiller c''est bredouiller, parler de façon incompréhensible. A ne pas confondre avec "berdouille" qui désigne la boue !'),
('Patois', 'texte', NULL, '« À la place d''eum'' barrette, j''avos su''m''tiête l''caudron à frites ». Qu''est-ce qu''une barrette ?', 'Une perruque', 'Une canne', 'Un chapeau de mineur', 'Une pince', 'C', 'La barrette est le vrai casque ou chapeau de protection que portaient les mineurs de fond, souvent en cuir bouilli !'),
('Patois', 'texte', NULL, '« Ajouque te, arlève te, claque eut''boudenne contre eul''mienne ! » Que signifie Ajouque te ?', 'Redresse-toi', 'Accroupis-toi', 'Embrasse-moi', 'Arrête-toi', 'B', 'S''ajouquer, c''est l''action de s''accroupir, ou s''asseoir sur ses talons ! La "boudenne" désignant le ventre.'),
('Patois', 'texte', NULL, 'On dit toujours : « Ch''est toudis ch''tchiot qui prind tout ! » Que désigne ch''tchiot ?', 'Le petit', 'Le toit', 'Les dents', 'Le chien', 'A', 'Le "tchiot" (ou "tiot"), c''est le petit, l''enfant. C''est le terme d''affection régional le plus célèbre !'),
('Patois', 'texte', NULL, '« T''as vu commint t''es arnequé avec tes fouffes ? » Que sont des fouffes ?', 'Des chaussures trouées', 'Des cheveux pas coiffés', 'Des vieux habits', 'Des lunettes sales', 'C', 'Les fouffes désignent les vieux vêtements, les fringues usées ou sales.'),
('Patois', 'texte', NULL, '« Armonte eut'' maronne, elle qué su'' tes gampes. » qu''est ce que la maronne ?', 'Ta pendule', 'Tes bretelles', 'Ton pantalon', 'Ta jupe', 'C', 'La "maronne" (ou marronne) est un grand classique du vocabulaire ch''ti pour désigner le pantalon !'),
('Patois', 'texte', NULL, '« I''n''faut pas que ch'' glaines i'' cantent pus fort qué ch''co ! »', 'Les poules', 'Les graines', 'Les chemises', 'Les femmes', 'A', 'Les "glaines" sont les poules. Le dicton signifiant que c''est le coq (l''homme) qui doit avoir de l''autorité !'),
('Patois', 'texte', NULL, '« Eut'' braïette alle est ouverte, t''n''ojieau i va s''involer ! »', 'Ta barquette', 'Ta baguette', 'Ta braguette', 'Ta sacoche', 'C', 'La "braïette" est la fameuse braguette. Un rappel utile avant de sortir de chez soi !'),
('Patois', 'texte', NULL, '« J''espère que mon quiz, vous n''allez pas le mette à luche ! »', 'Au diable', 'Au feu', 'À la poubelle', 'En pause', 'C', 'Mettre "à l''uche" (ou à luche), c''est jeter à la poubelle, mettre aux ordures. Ne jetez pas BaraQuiz !');
