-- ============================================================
-- BARAQUIZ — Base de données de 400 questions
-- Thèmes : Hauts-de-France (Nord-Pas-de-Calais, Picardie)
-- ============================================================

SET NAMES utf8mb4;
-- Table utilisateurs (if not exists)
CREATE TABLE IF NOT EXISTS utilisateurs (
    id INT AUTO_INCREMENT PRIMARY KEY,
    prenom VARCHAR(100) NOT NULL,
    nom VARCHAR(100) NOT NULL,
    mail VARCHAR(191) NOT NULL UNIQUE,
    mdp VARCHAR(255) NOT NULL
);

-- Table user_answers (pour les stats)
CREATE TABLE IF NOT EXISTS user_answers (
    id INT AUTO_INCREMENT PRIMARY KEY,
    id_utilisateur INT NOT NULL,
    theme VARCHAR(255) NOT NULL,
    is_correct INT NOT NULL,
    total INT NOT NULL,
    date_partie TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (id_utilisateur) REFERENCES utilisateurs(id) ON DELETE CASCADE
);

-- Table questions (Dropping it entirely allows to cleanly reinsert the 400 rows and reset AUTO_INCREMENT)
DROP TABLE IF EXISTS questions;
CREATE TABLE questions (
    id INT AUTO_INCREMENT PRIMARY KEY,
    theme VARCHAR(255) NOT NULL,
    type_media VARCHAR(50) NOT NULL DEFAULT 'texte',
    url_media VARCHAR(2048),
    question TEXT NOT NULL,
    reponse_A TEXT NOT NULL,
    reponse_B TEXT NOT NULL,
    reponse_C TEXT NOT NULL,
    reponse_D TEXT NOT NULL,
    bonne_reponse CHAR(1) NOT NULL,
    anecdote TEXT
);

